<template>
	<view>
		<u-popup v-model="showShare" mode="bottom" class="share-popup"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20">
			<view class="popup-content">
				<view class="share-title">
					<view class="title">
						{{sharetitle}}
					</view>
				</view>
				<view class="share-box">
					<view class="share-item" v-for="(item,index) in shareList" :key="index" @click="clickShare(item)">
						<image class="img" :src="item.img" mode="aspectFit"></image>
						<view class="text">
							{{item.title}}
						</view>
					</view>
				</view>
				<view class="close">
					<view @click="showShare = false">取消</view>
				</view>
			</view>
		</u-popup>
		<pointShare :show="pointShareShow" @close="pointShareShow =false"></pointShare>
		<u-modal v-model="showShareCopy" @confirm="clickShareCopy" ref="showShareCopy_box" :async-close="true"
			:show-cancel-button="true" title="专属链接" confirm-text="复制"
			:confirm-style="{color:'#e5cfb4',fontWeight:600,border:'2rpx solid #f4f5f8'}">
			<view class="slot-content">
				<view class="copy-box">
					<swiper :current="current" @change="changeswiper">
						<swiper-item class="swiper-item" v-for="(item, index) in shareCopyList" :key="index">
							<view class="view-box">
								<text class="text">
									{{item.title}}
								</text>
							</view>
						</swiper-item>
					</swiper>
					<view class="swiper-left" v-if="current>0" @click="clickSwiperLeft">
						<u-icon size="40" name="arrow-left"></u-icon>
					</view>
					<view class="swiper-right" v-if="current < shareCopyList.length -1" @click="clickSwiperRight">
						<u-icon size="40" name="arrow-right"></u-icon>
					</view>
				</view>
			</view>
		</u-modal>
		<l-painter ref="lpainter" isCanvasToTempFilePath @success="path = $event"
			custom-style="position: fixed; left: 200%;" />
		<u-mask :show="showGoPoster" @click="showGoPoster = false" :custom-style="{
					textAlign:'center'
				}">
			<view class="" @click.stop solt="default">
				<image :src="path" @longpress="savePosterPath(path)" v-if="true" class="poster-img" mode="widthFix">
				</image>
				<u-icon @click="showGoPoster= false" :custom-style="{
										    position: 'fixed',
										    top: '132rpx',
										    zIndex: 1200,
										    right: '56rpx',
									}" size="40" name="close-circle" color="#fff"></u-icon>
				<view class="ImageShar">请长按图片保存到相册或截图分享哦</view>
			</view>
		</u-mask>
	</view>
</template>

