																fontWeight: "normal",
																textDecoration: "line-through",
																color: "#999999"
															}
														},
														{
															text: "￥",
															type: "text",
															css: {
																verticalAlign: "bottom",
																// marginLeft: "20rpx",
															},
														}, {
															text: "39",
															type: "text",
															css: {
																verticalAlign: "bottom",
																fontSize: "58rpx"
															},
														}, {
															text: ".39",
															type: "text",
															css: {
