															},
														},

														// {
														// 	text: "扫码购买",
														// 	type: "text",
														// 	css: {
														// 		position: "absolute",
														// 		bottom: "0",
														// 		right: "0",
														// 		verticalAlign: "bottom",
														// 		// paddingLeft: "10rpx",
														// 		marginLeft: "20rpx",
														// 		border: "2rpx solid",

														// 		fontWeight: "normal",
														// 		// textDecoration: "line-through",
														// 		padding: "8rpx 14rpx",
														// 		color: "#000"
														// 	}
														// },
													],
												},


											],
											type: "view"
										},


									],

									type: "view"
								},


							],
							type: "view"
						}
					]
				},
				colorList: [
					'linear-gradient(25deg, #1be9c7 0%, #9be99d 33%, #d4e870 66%, #ffe637 100%)',
					'linear-gradient(25deg, #3204ad 0%, #7a2ac1 33%, #b34dd5 66%, #e971e9 100%)',
					'linear-gradient(25deg, #6b24f2 0%, #7972ea 33%, #74aee1 66%, #50e7d5 100%)',
					'linear-gradient(25deg, #17a014 0%, #7fab1e 33%, #c1b228 66%, #feb632 100%)',
					'linear-gradient(25deg, #cd3577 0%, #d97b87 33%, #e1b496 66%, #e2eaa5 100%)',
					'linear-gradient(25deg, #2924e7 0%, #8d5dda 33%, #c295ca 66%, #ecceb7 100%)',
					'linear-gradient(25deg, #d77c8b 0%, #ba8ea7 33%, #939dc3 66%, #50abe0 100%)',
					'linear-gradient(25deg, #d46146 0%, #bd7f6f 33%, #999999 66%, #53b0c5 100%)',
					'linear-gradient(25deg, #c04561 0%, #d6818e 33%, #e6b8be 66%, #f0f0f0 100%)',
					'linear-gradient(25deg, #7861f7 0%, #a88ff6 33%, #cfbff4 66%, #f0f0f0 100%)',
					'linear-gradient(25deg, #2b89b2 0%, #7ba296 33%, #a9bd78 66%, #ced950 100%)',
					'linear-gradient(25deg, #3f64ca 0%, #8690d8 33%, #bdbfe4 66%, #f0f0f0 100%)',
				],
			};
		},
		methods: {
			show(shareData) {
				this.shareData = Object.assign({}, shareData)

				this.queryForm.goods_id = shareData.goods_id
				this.queryForm.linkUrl = this.getLinkUrl()
				this.shareConfig()
			},
			getLinkUrl() {
				let linkUrl = ''
				//#ifdef H5
				if (typeof window.entryUrl === 'undefined' || window.entryUrl === '') {
					window.entryUrl = location.href
				}
				linkUrl = /(Android)/i.test(navigator.userAgent) ? location.href : window.entryUrl
				//#endif
				return linkUrl
			},
			async pathToBase64(path) {
				return new Promise(async (resovle, rejct) => {

					const canvas = document.createElement('canvas')
					const canvasContext = canvas.getContext('2d')
					var img = new Image()
					img.crossOrigin = "anonymous"
					img.src = path
					img.onload = function() {
						canvas.width = img.width
						canvas.height = img.height
						canvasContext.drawImage(img, 0, 0)
						const base64Data = canvas.toDataURL('image/png')
						// console.log(base64Data);
						// console.log(base64Data,canvasContext.getImageData(0,0,img.width,img.height))
						resovle(base64Data)
					}
					img.onerror = async () => {
						//获取失败了就请求接口
						const {
							base64,
						} = await this.$u.api.download({
							id: this.shareData.goods_id
						})
						if (base64) {
							const base64Data = 'data:image/png;base64,' + base64
							resovle(base64Data)
						} else {
							rejct('转换base64失败')
						}
					}

					// fetch(path).then(r=>r.arrayBuffer()).then(arrBuffer=>{
					// 	const	base64	= btoa(new Uint8Array(arrBuffer).reduce((data, byte) => data + String.fromCharCode(byte), '')),
					// 		img	= new Image(),
					// 		source	= 'data:image/png;base64,' + base64;
					// 		resovle(source)
					// 	//ESD.$('body').element.append( img );
					// 	console.log(source);
					// });
					// try {

					// 	uni.request({
					// 	                url:path,
					// 	                responseType: 'arraybuffer',
					// 	                header: {
					// 	                    // 'Authorization': 'Bearer ' + $store.state.app.token
					// 	                },
					// 	                success: (res) => {
					// 	                    const arrayBuffer = res.data
					// 	                    let base64= 'data:image/jpeg;base64,'+ uni.arrayBufferToBase64(arrayBuffer)
					// 						resovle(base64)
					// 	                }
					// 	            });


					// } catch (e) {
					// 	console.log(e);
					// }




					// console.log(base64Data,canvasContext.getImageData(0,0,img.width,img.height))
					// resovle(base64Data)


					// var xhr = new XMLHttpRequest();
					// xhr.open('get', path, true);
					// xhr.responseType = 'blob';
					// xhr.onload = function () {

					// console.log();
					// 		const blob = URL.createObjectURL(path);

					// 		resolve(`data:image/png;base64,${btoa(blob)}`);

					// };
					// xhr.send();

					// const reader = new FileReader()
					//  reader.onload = () => {
					//    const img = new Image()
					//    img.src = reader.result
					//    img.onload = () => {
					//      const canvas = document.createElement('canvas')
					//      canvas.width = img.width
					//      canvas.height = img.height
					//      const ctx = canvas.getContext('2d')
					//      ctx.drawImage(img, 0, 0)
					//      const base64data = canvas.toDataURL('image/png')
					//      console.log(base64data)
					// 	 resovle(base64Data)
					//    }
					//  }
					//  reader.readAsDataURL(path) 


				})
			},
			async shareConfig() {
				const {
					shareList,
					sharetitle,
					page_share_url,
					sharewxgzhConfig
				} = await this.$u.api.shareConfig(this.queryForm)
				this.showShare = true
				this.shareList = shareList
				this.sharetitle = sharetitle
				this.pageShareUrl = page_share_url
				//#ifdef H5
				if (this.$util.browserType('weixin')) {
					if (!Array.isArray(sharewxgzhConfig)) {
						this.wxShare(sharewxgzhConfig, this.getWxShareData())
					}
				}
				//#endif
			},
			getWxShareData() {
				if (this.queryForm.linkUrl.indexOf('&pid=') === -1) {
					this.pageShareUrl = this.queryForm.linkUrl + '&pid=' + this.userinfo.id;
				}
				return {
					title: this.shareData.goods_name,
					// desc: '现价:' + this.shareData.goods_price + "\r\n原价:" + Number(this.shareData
					// 		.default_level_price) >
					// 	Number(this.shareData.face_value) ? this.shareData.default_level_price : this.shareData.face_value,
						
						desc: '现价:' + this.shareData.face_value + "\r\n原价:" + this.shareData
							.default_level_price,
					linkUrl: this.pageShareUrl,
					imgUrl: this.$util.img(this.shareData.goods_img),
				}
			},
			async wxShare(res, options) {
				//配置
				await jWeixin.config({
					debug: res.debug ? true : false, //根据服务端来控制是否开启调试模式
					appId: res.appId,
					timestamp: res.timestamp,
					nonceStr: res.nonceStr,
					signature: res.signature,
					jsApiList: res.jsApiList,
				});
				//分享的触发动作必须写再ready里面
				jWeixin.ready(() => {
					//配置分享数据
					let shareData = {
						title: options.title || "", //分享的标题
						desc: options.desc || "", //分享的描述
						link: options.linkUrl, //分享的链接
						imgUrl: options.imgUrl || "", //分享的图片链接
						success(response) {
							//配置成功之后的回调（并不是分享成功之后的回调，这个地方是个坑，要注意下）
							console.log(response);
						},
					};
					jWeixin.updateAppMessageShareData(shareData)
					jWeixin.updateTimelineShareData(shareData)
					jWeixin.onMenuShareAppMessage(shareData)
					jWeixin.onMenuShareTimeline(shareData)
				})
			},
			async clickShare(item) {
				let shareData = this.getWxShareData()
				let that = this
				switch (item.type) {
					case 'weixinpeng':
						//#ifdef APP
						uni.share({
							provider: "weixin",
							scene: "WXSceneTimeline",
							type: 0,
							href: this.pageShareUrl, // 分享跳转的链接
							title: shareData.title, // 分享标题
							summary: shareData.desc, // 分享内容文字
							imageUrl: this.$util.img(shareData.imgUrl), //分享封面图片
							success: function(res) {
								// 此处是调起微信分享成功的回调
								console.log(res);
								that.showShare = false;
							},
							fail: function(err) {
								// 此处是调起微信分享失败的回调
								console.log(err);
								that.showShare = false;
							}
						})
						//#endif
						break
					case 'weixin':
						//#ifdef H5
						//微信浏览器
						if (this.$util.browserType('weixin')) {
							//微信指引
							this.pointShareShow = true
							this.showShare = false
						} else {

						}
						//#endif
						//#ifdef APP
						uni.share({
							provider: "weixin",
							scene: "WXSceneSession",
							type: 0,
							href: this.pageShareUrl, // 分享跳转的链接
							title: shareData.title, // 分享标题
							summary: shareData.desc, // 分享内容文字
							imageUrl: this.$util.img(shareData.imgUrl), //分享封面图片
							success: function(res) {
								// 此处是调起微信分享成功的回调
								console.log(res);
								that.showShare = false;
							},
							fail: function(err) {
								// 此处是调起微信分享失败的回调
								console.log(err);
								that.showShare = false;
							}
						})
						//#endif
						break
					case 'link':
						this.shareCopyList = item.linkList
						this.showShareCopy = true
						this.showShare = false
						break
					case 'img':
						this.share()
						break
					case 'goodsimg':
						//商品海报

						await this.goPoster().then((res) => {
							this.showShare = false
							this.showGoPoster = true
						}).catch((res) => {
							this.$util.msg('生成海报失败')
						})


						break
				}
			},
			//分享
			share() {
				this.$util.on('/pages/common/poster?share_from=1&goods_id=' + this.shareData.goods_id)
			},
			// 复制链接-start
			clickSwiperLeft() {
				if (this.current > 0) {
					this.current--
				}
			},
			clickSwiperRight() {
				if (this.current < this.shareCopyList.length - 1) {
					this.current++
				}
			},
			changeswiper(e) {
				this.current = e.detail.current
			},
			clickShareCopy() {
				uni.setClipboardData({
					// data: this.shareCopyList[this.current].title + this.shareCopyList[this.current].url,
					data: this.shareCopyList[this.current].title,
					success: function() {
						uni.showToast({
							title: '复制链接成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})

				this.$refs.showShareCopy_box.clearLoading()
				this.showShareCopy = false
			},
			// 复制链接-end
			async goPoster() {
				this.poster.css.background = this.colorList[this.shareData.goods_id % 10]
				this.poster.views[0].views[0].text = this.userinfo.company
				// this.poster.views[0].views[0].text= this.userinfo.headurl_img
				// this.poster.views[0].src = this.userinfo.headurl_img

				// this.poster.views[1].views[0].text = this.userinfo.company
				// console.log(this.poster);
				this.poster.views[1].views[0].src = await this.pathToBase64(this.shareData.goods_img)

				// this.poster.views[1].views[1].views[1].views[1].views[0].text = '￥' + Number(this.shareData
				// 		.default_level_price) > Number(this.shareData.face_value) ? this.shareData
				// 	.default_level_price : Number(this
				// 		.shareData.face_value)
				// 	.toFixed(2)
				this.poster.views[1].views[1].views[1].views[1].views[2].text = this.shareData.default_level_price
					.split('.')[0]

				this.poster.views[1].views[1].views[1].views[1].views[3].text = '.' + Number(this.shareData
					.default_level_price).toFixed(2).split('.')[1]

				this.poster.views[1].views[1].views[1].views[0].views[0].text = this.shareData.goods_name

				const {
					url
				} = await this.$u.api.getwxgzhqrcode({
					goods_id: this.shareData.goods_id,
					type: 4
				})
				this.poster.views[1].views[1].views[0].text = url

				this.$refs['lpainter'].render(this.poster)
			},
			savePosterPath(path) {
				//#ifndef H5
				uni.showLoading({
					mask: true,
					title: '保存中...',

				})
				uni.saveImageToPhotosAlbum({
					filePath: path,
					success: (res) => {
						uni.hideLoading()
						this.$util.msg('图片已保存')
					},
					fail: (err) => {
						uni.hideLoading()
						this.$util.msg('图片保存失败')
					}
				})
				//#endif
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	::v-deep {
		.poster-img>img {
			-webkit-touch-callout: default !important;
		}
	}


	.copy-box {
		padding: 20rpx 40rpx;
		position: relative;

		.swiper-item {
			background: #fbf3ea;
			border-radius: 20rpx;

			.view-box {

				padding: 14rpx;
				font-size: 28rpx;
				color: #ad916e;

				.text {
					word-break: break-all;
				}
			}
		}

		.swiper-left {
			position: absolute;
