<template>
	<view class="join-cart-btn" @click.stop>
		<view class="btn-wrap" @click="doJoin">
			<text>加入购物车</text>
			<u-badge class="badge" type="error" :count="count" absolute :offset="[-10,-10]"
				bgColor="var(--view-theme)"></u-badge>
		</view>
		<!-- <template v-else>
			<view class="number-box" v-if="count">
				<view class="reduce-item" @click="decrease">
					<u-icon name='minus' />
				</view>
				<view class="text-item">{{count}}</view>
				<view class="add-item">
					<u-icon name='plus' @click="increase" />
				</view>
			</view>
			<view v-else>
				<view class="cart-icon-box" @click="join">
					<u-icon name='shopping-cart' />
				</view>
			</view>
		</template> -->
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			goodsId: {
				type: Number,
				required: true,
				default: 0,
			},
			// 0单规格，1多规格
			// specType: {
			// 	type: Number,
			// 	required: true,
			// 	default: 0,
			// },
			// 购物车数量
			count: {
				type: Number,
				default: 0,
			},
			numType: {
				type: Number,
				default: 1
			},
			numCount: {
				type: String,
				default: ''
			},
			startCount: {
				type: Number,
				default: 1
			},
			endCount: {
				type: Number,
				default: 100
			}
		},
		data() {
			return {

			}
		},
		computed: {

		},
		mounted() {

		},
		methods: {
			doJoin() {
				this.$emit('join', {
					goods_id: this.goodsId,
					num: this.getNum(),
				})
			},
			getNum() {
				let num = 1
				if (this.numType == 1) {
					if (this.startCount > num) {
						num = this.startCount
					}
				} else if (this.numType == 2) {
					const numList = this.parseNumCount(this.numCount)
					if (numList.length) {
						num = numList[0].value
					}
				}
				return num
			},
			parseNumCount(str) {
				let arr = str.split(',')
				let re = []

				arr.forEach(item => {
					if (item.indexOf('-') != -1) {
						let tmp = item.split('-')
						for (let i = tmp[0]; i <= tmp[1]; i++) {
							re.push({
								value: Number(i),
								label: i
							})
						}
					} else {
						re.push({
							value: Number(item),
							label: item
						})
					}
				})
				return re
			},
			decrease() {},
			increase() {}
		},
	}
</script>

<style scoped lang="scss" scoped>
	.join-cart-btn {
		.btn-wrap {
			width: 172rpx;
			height: 58rpx;
			position: relative;
			color: #fff;
			font-size: 24rpx;
			border-radius: 30rpx;
			display: flex;
			align-items: center;
			justify-content: center;
			background-color: var(--view-theme);

			.badge {
				border: 2rpx solid #fff;
			}
		}

		.number-box {
			display: flex;
			align-items: center;

			.reduce-item {
				width: 48rpx;
				height: 48rpx;
				color: #333;
				border-radius: 30rpx;
				background-color: #f5f5f5;
				display: flex;
				justify-content: center;
				align-items: center;
			}

			.text-item {
				padding: 0 20rpx;
				color: #333;
				font-size: 30rpx;
			}

			.add-item {
				width: 48rpx;
				height: 48rpx;
				color: #fff;
				border-radius: 30rpx;
				background-color: var(--view-theme);
				display: flex;
				justify-content: center;
				align-items: center;
			}
		}

		.cart-icon-box {
			width: 48rpx;
			height: 48rpx;
			color: #fff;
			border-radius: 30rpx;
			background-color: var(--view-theme);
			display: flex;
			justify-content: center;
			align-items: center;
		}
	}
</style>