<template>
	<scroll-view @touchmove.stop scroll-x class="scroll_content" :style="{width:'100vw'}">
		<view class="spec-box">
			<view class="spec-list" v-for="item,index in specKeyData" :key="index">
				<span class="attr-name">{{ item.attr_name }}</span>
				<view class="radio-txt-list" v-if="item.t == 1">
					<view class="radio-txt-item" :style="{
							opacity:item2.canChoose?1:0.4
						}" :class="{checked:selectedIndex[index] == index2}" @click="handelClick(index,index2,item2)"
						v-for="item2,index2 in item.attr_values" :key="index2">
						<view class="name">{{item2.name}}</view>
					</view>
				</view>
				<view class="radio-img-list" v-else-if="item.t == 2">
					<scroll-view :scroll-x="true" class="scroll-view_H">
						<view class="radio-img-item" :style="{
							opacity:item2.canChoose?1:0.4
						}" :class="{checked:selectedIndex[index] == index2}" @click="handelClick(index,index2,item2)"
							v-for="item2,index2 in item.attr_values" :key="index2">
							<view class="img">
								<u-image width="100%" height="220rpx" :src="item2.img"></u-image>
								<view class="txt ">
									<text class="line2">{{item2.name}}</text>
								</view>
								<text class="icon" @click.stop><u-icon name="search" size="28"
										@click="preview(item2.img)" /></text>
							</view>
						</view>
					</scroll-view>
				</view>
			</view>
		</view>
	</scroll-view>
</template>

<script>
	import _ from 'lodash'

	export default {
		components: {

		},
		props: {
			specKey: {
				type: Array,
				default: () => {
					return []
				}
			},
			specValue: {
				type: [String, Object],
				default: ''
			},
			// 选中的商品规格值，不是商品规格键的值
			selectedSpecValue: {
				type: Object,
				default: () => {
					return {}
				}
			},
			readOnly: {
				type: Boolean,
				default: false,
			},
		},
		data() {
			return {
				selectedIndex: [],
			};
		},
		computed: {
			specValueData() {
				return typeof this.specValue == 'string' ? JSON.parse(this.specValue) : this.specValue
			},
			specKeyData() {
				return this.specKey.map((item, index) => {
					item.attr_values.forEach((item1, index1) => {
						let arr = []
						this.selectedIndex.forEach((items, indexs) => {
							if (index == indexs) {
								arr.push(this.specKey[indexs].attr_values[index1].name)
							} else {
								arr.push(this.specKey[indexs].attr_values[items].name)
							}
						})
						if (this.specValueData[arr.join(',')] && this
							.specValueData[arr
								.join(',')].stock_num > 0) {
							item1.canChoose = true;
						} else {
							item1.canChoose = false;
							//第一个规格处理选项
							if (index == 0) {
								for (let key in this.specValueData) {
									if (key.indexOf(item1.name) === 0 && this.specValueData[key]
										.stock_num > 0) {
										item1.canChoose = true
									}
								}
							}
						}
					})
					return item
				})
			},
			// 笛卡尔商品规格集合
			specSet() {
				let specs = this.specKey.map(item => {
					let tmp = {
						name: item.attr_name,
						value: []
					}
					tmp.value = item.attr_values.map(v => {
						return v.name
					})
					return tmp
				})
				return this.combineSpecs(specs)
			},
			// 有效的规格项索引
			validSpecIndex() {
				//根据规格值，排除不存在的规格项
				let filter_specs = this.specSet.filter(item => {
					return (item.join(',') in this.specValueData) && this.specValueData[item.join(',')].stock_num
				}).map(item => {
					return item.map((v, i) => {
						return this.specKey[i].attr_values.findIndex(s => s.name == v)
					})
				})
				return filter_specs
			},
			// 无效的规格项索引
			inValidSpecsIndex() {
				//根据规格值，排除存在的规格项
				let filter_specs = this.specSet.filter(item => {
					return !(item.join(',') in this.specValueData) || !this.specValueData[item.join(',')].stock_num
				}).map(item => {
					return item.map((v, i) => {
						return this.specKey[i].attr_values.findIndex(s => s.name == v)
					})
				})
				return filter_specs
			}
		},
		watch: {
			specKey: {
				handler(nv) {
					if (this.selectedSpecValue.suk) {
						let arr = this.selectedSpecValue.suk.split(',')
						arr.forEach((item, index) => {
							let idx = this.specKey[index].attr_values.findIndex(attr => attr.name == item)

							if (idx != -1) {
								this.selectedIndex[index] = idx
							} else {
								this.selectedIndex[index] = 0
							}
						})
					} else {
						this.selectedIndex = [...this.validSpecIndex[0]]
					}
					this.$emit('change', this.getSpecValue())
				},
				immediate: true,
			},
		},
		created() {

		},
		mounted() {

		},
		methods: {
			preview(url) {
				uni.previewImage({
					urls: [url],
					current: url,
				})
			},
			handelClick(index, index2, item2) {
				if (item2.canChoose && this.selectedIndex[index] != index2) {
					this.$set(this.selectedIndex, index, index2)
					let specValue = this.getSpecValue()
					//没有对象就重置选项
					if (specValue && specValue.id) {
						this.$emit('change', specValue)
					} else {
						if (index == 0) {
							//获取有效的规格
							for (let key in this.specValueData) {
								if (key.indexOf(item2.name) === 0) {
									let arr = this.specValueData[key].suk.split(',')
									arr.forEach((aitem, aindex) => {
										let idx = this.specKey[aindex].attr_values.findIndex(attr => attr.name ==
											aitem)
										if (idx != -1) {
											this.$set(this.selectedIndex, aindex, idx)
										} else {
											this.$set(this.selectedIndex, index, idx)
										}
									})
									break;
								}
							}
							this.$emit('change', this.getSpecValue())
						}
					}
				}
			},
			// 获取规格键
			getSpecKey() {
				let arr = []
				this.selectedIndex.forEach((item, index) => {
					if (item == -1) arr.push('')
					else arr.push(this.specKey[index].attr_values[item].name)
				})
				return arr
			},
			// 获取规格值
			getSpecValue() {
				let arr = this.getSpecKey()

				if (arr.join(',') in this.specValueData)
					return this.specValueData[arr.join(',')]
				else
					return {}
			},
			combineSpecs(specs) {
				if (specs.length === 0) {
					return [
						[]
					];
				} else {
					const [head, ...tail] = specs;
					const rest = this.combineSpecs(tail);
					const pairs = head.value.map(value => rest.map(r => [value, ...r]));
					return [].concat(...pairs);
				}
			},
		},
	};
</script>

<style scoped lang="scss" scoped>
	.spec-box {
		display: flex;
		flex-direction: column;
		gap: 20rpx;
		margin-top: 10rpx;
		padding: 0 30rpx;

		.spec-list {
			display: flex;
			flex-direction: column;

			.attr-name {
				font-size: 28rpx;
				color: #333333;
				padding: 10rpx 0;
			}
		}
	}

	.radio-txt-list {
		display: flex;
		align-items: center;
		flex-wrap: wrap;
		gap: 10rpx;
		flex: 1;
		padding-bottom: 10rpx;

		.radio-txt-item {
			font-size: 24rpx;
			position: relative;
			cursor: pointer;
			user-select: none;
			display: flex;
			align-items: center;
			justify-content: center;

			.name {
				border: 1rpx solid rgba(0, 0, 0, 0);
				overflow: hidden;
				position: relative;
				cursor: pointer;
				border-radius: 6rpx;
				display: inline-flex;
				align-items: center;
				justify-content: center;
				min-width: 96rpx;
				background: #F7F8FA;
				padding: 10rpx 20rpx;
			}
		}

		.checked {
			color: #ee0a24;

			.name {
				border: 1rpx solid #ee0a24;
				background-color: #FFF2F2;
				color: #FF4444;
			}
		}
	}

	.scroll-view_H {
		white-space: nowrap;
		width: 100%;
	}

	.radio-img-list {
		display: flex;
		align-items: center;
		gap: 10rpx;
		flex: 1;

		.radio-img-item {
			border: 1rpx solid rgba(0, 0, 0, 0);
			border-radius: 10rpx;
			font-size: 24rpx;
			position: relative;
			cursor: pointer;
			user-select: none;
			display: inline-flex;
			align-items: center;
			justify-content: center;
			overflow: hidden;
			width: 200rpx;

			.img {
				flex: 1;
				display: flex;
				align-items: center;
				justify-content: center;
				flex-direction: column;
				position: relative;

				&>.txt {
					display: flex;
					align-items: center;
					justify-content: center;
					width: 100%;
					height: 80rpx;
					padding: 8rpx;
					border-bottom-left-radius: 10rpx;
					border-bottom-right-radius: 10rpx;
					background-color: #F7F8FA;
					white-space: normal;
				}

				&>.icon {
					position: absolute;
					right: 5rpx;
					top: 5rpx;
					width: 40rpx;
					height: 40rpx;
					background-color: rgba(0, 0, 0, 0.4);
					border-radius: 2px;
					text-align: center;
					color: #fff;
				}
			}
		}

		.radio-img-item+.radio-img-item {
			margin-left: 10rpx;
		}

		.checked {
			border: 1rpx solid #ee0a24;
			color: #ee0a24;

			.img {
				&>.txt {
					background-color: #FFF2F2;
				}
			}
		}
	}
</style>