<template>
	<view>
		<fabV2 ref="fab" :pattern="patternConfig" :content="contentConfig" :horizontal="horizontalConfig"
			:vertical="verticalConfig" :direction="directionConfig" @trigger="trigger" />
	</view>
</template>

<script>
	import CompMixin from '../mixins/comp.js'
	import fabV2 from '@/components/fabV2'

	export default {
		name: 'FabMenu',
		components: {
			fabV2
		},
		mixins: [CompMixin],
		data() {
			return {

			};
		},
		computed: {
			patternConfig() {
				const items = this.getAttr('patternConfig.items', [])
				const re = {}
				items.forEach(item => {
					if (item.hastTransform) {
						re[item.field] = {
							value: item.value,
							transform: item.transform
						}
					} else
						re[item.field] = item.value
				})

				return re
			},
			directionConfig() {
				const tabVal = this.getAttr('directionConfig.tabVal', 0)
				const tabList = this.getAttr('directionConfig.tabList', [])
				if (tabList[tabVal]) {
					if (tabVal)
						return 'vertical'
					else
						return 'horizontal'
				} else
					return 'horizontal'
			},
			horizontalConfig() {
				const tabVal = this.getAttr('horizontalConfig.tabVal', 0)
				const tabList = this.getAttr('horizontalConfig.tabList', [])
				if (tabList[tabVal]) {
					if (tabVal)
						return 'right'
					else
						return 'left'
				} else
					return 'left'
			},
			verticalConfig() {
				const tabVal = this.getAttr('verticalConfig.tabVal', 0)
				const tabList = this.getAttr('verticalConfig.tabList', [])
				if (tabList[tabVal]) {
					if (tabVal)
						return 'top'
					else
						return 'bottom'
				} else
					return 'bottom'
			},
			contentConfig() {
				const list = this.getAttr('contentConfig.list', [])
				return list
			},
		},
		mounted() {

		},
		methods: {
			getItemByField(arr, field) {
				return arr.find((item) => item.field == field)
			},
			trigger(e) {
				// this.contentConfig[e.index].active = !e.item.active

				this.$refs['fab'].close()
				this.$util.on(e.item.link)
			},
		}
	};
</script>

