<template>
	<u-popup v-model="popupShow" mode="top" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.1)'}" :border-radius="20"
		:closeable="false" :z-index="100" :duration="1" @close="close" @open="open">
		<view class="popup-content">
			<view class="search-box">
				<u-search placeholder="请输入商品名称" :show-action="false" margin="0 32rpx" height="58"
					:input-style="{fontSize:'24rpx'}" />
				<view class="search-mask" @click="searchClick"></view>
			</view>
			<view class="list-box">
				<view class="title">{{currCateName}}</view>
				<view class="list-wrap">
					<view class="list-item line1" :class="{active:activeIndex === index}" v-for="item,index in list"
						:key="index" @click="handelItemClick(item,index)">
						{{item.name}}
					</view>
				</view>
			</view>
			<view class="close-box" @click="popupShow=false">
				<text>点击收起</text>
				<u-icon name="arrow-up" />
			</view>
		</view>
	</u-popup>
</template>

<script>
	export default {
		components: {

		},
		props: {
			value: {
				type: Boolean,
				default: false,
			},
			activeIndex: {
				type: Number,
				default: 0,
			},
			list: {
				type: Array,
				default: () => ([])
			},
		},
		data() {
			return {

			}
		},
		computed: {
			popupShow: {
				get() {
					return this.value
				},
				set(val) {
					this.$emit('input', val)
				},
			},
			currCateName() {
				return this.list[this.activeIndex] ? this.list[this.activeIndex].name : ''
			},
		},
		watch: {

		},
		methods: {
			open() {},
			close() {

			},
			searchClick() {
				this.$util.on('/pages/search/search')
			},
			handelItemClick(row, index) {
				if (row && row.is_jump_url == 1) {
					this.$util.on(row.jump_url)
					return
				}
				if (this.activeIndex === index)
					return

				this.$emit("update:active-index", index)
				this.$emit("change", row)
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.popup-content {
		background-color: #fff;

		.search-box {
			position: relative;
			padding: 16rpx 0;

			.search-mask {
				position: absolute;
				width: 100%;
				height: 100%;
				left: 0;
				top: 0;
			}
		}

		.list-box {
			padding: 30rpx;

			.title {
				font-size: 32rpx;
				color: rgba(51, 51, 51, 1);
			}

			.list-wrap {
				display: grid;
				grid-template-columns: repeat(4, minmax(0, 1fr));
				grid-template-rows: none;
				gap: 24rpx;
				margin-top: 24rpx;

				.list-item {
					background-color: rgba(245, 245, 245, 1);
					width: 154rpx;
					height: 56rpx;
					color: rgba(51, 51, 51, 1);
					font-size: 24rpx;
					border-radius: 30rpx;
					display: block;
					line-height: 52rpx;
					text-align: center;
					border: 2rpx solid #fff;
				}

				.active {
					color: var(--view-theme);
					background: var(--view-minorColorT);
					border: 2rpx solid var(--view-theme);
				}
			}
		}

		.close-box {
			height: 80rpx;
			display: flex;
			align-items: center;
			justify-content: center;
			color: rgba(153, 153, 153, 1);
			gap: 8rpx;
		}
	}
</style>