<template>
	<view class="animate-box">
		<view class="animate-wrap" :class="[animateName,{loop:isLoop}]"
			:style="{'animation-duration': `${duration}ms`,'border-radius':`${borderRadius}rpx`}">
			<slot></slot>
		</view>
	</view>
</template>

<script>
	export default {
		name: 'my-animation',
		props: {
			animate: {
				type: String,
				required: true,
			},
			isLoop: {
				type: Boolean,
				default: true,
			},
			duration: {
				type: Number,
				default: 500
			},
			borderRadius: {
				type: Number,
				default: 0
			}
		},
		data() {
			return {

			}
		},
		computed: {
			animateName() {
				return `animate-${this.animate}`
			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.animate-box {
		.animate-wrap {
			display: inline-block;
		}

		.animate-twinkle {
			position: relative;
			line-height: 1;

			&:after,
			&:before {
				width: 60px;
				height: 60px;
				content: "";
				box-sizing: border-box;
				border: 4px solid rgba(255, 255, 255, .6);
				position: absolute;
				border-radius: 30px;
				right: 50%;
				margin-top: -15px;
				margin-right: -30px;
				z-index: 1;
				transform: scale(0);
				animation: twinkle 2s ease-out infinite
			}

			&:before {
				animation-delay: .4s
			}
		}

		.animate-flicker {
			position: relative;
			overflow: hidden;

			&:after {
				width: 100px;
				height: 60px;
				position: absolute;
				left: 0;
				top: 0;
				opacity: .73;
				content: "";
				background-image: linear-gradient(106deg, rgba(232, 224, 255, 0) 24%, #e8e0ff 91%);
				animation: flicker 1.5s linear infinite;
				transform: skew(-20deg);
				filter: blur(3px)
			}
		}

		.loop {
			animation-iteration-count: infinite;
		}
	}

	.animate-box [class*=animate-] {
		animation-duration: .5s;
		animation-timing-function: ease-out;
		animation-fill-mode: both
	}

	@keyframes twinkle {
		0% {
			transform: scale(0)
		}

		20% {
			opacity: 1
		}

		50%,
		to {
			transform: scale(1.4);
			opacity: 0
		}
	}

	@keyframes flicker {
		0% {
			transform: translate(-100px) skew(-20deg)
		}

		40%,
		to {
			transform: translate(150px) skew(-20deg)
		}
	}
</style>