<template>
	<view class="comp-box" :style="[compStyle2]">
		<view class="comp-wrap" :style="[compWrapStyle2]">
			<view class="content-box" :style="[compContentStyle2]">
				<view class="title">
					<u-image :src="imgConfig" width="48rpx" height="48rpx" />
					<span>{{ tipConfig }}</span>
				</view>
				<view class="button" @click="$util.on(userinfo.vip_url)" v-if="userinfo.has_vip">{{ buttonText2Config }}
				</view>
				<view class="button" @click="$util.on(userinfo.vip_url)" v-else>{{ buttonText1Config }}</view>
			</view>
		</view>
	</view>
</template>

<script>
	import CompMixin from '../mixins/comp.js'
	export default {
		name: 'VipBanner',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {

			}
		},
		options: {
			styleIsolation: 'shared'
		},
		computed: {
			// 组件容器样式
			compStyle2() {
				const re = {
					marginTop: this.mbConfig,
					paddingTop: this.topConfig,
					paddingBottom: this.bottomConfig,
					paddingLeft: this.prConfig,
					paddingRight: this.prConfig,
					height: `${this.heightConfig*2}rpx`,
					backgroundColor: this.bottomBgColor,
				}
				return re
			},
			compWrapStyle2() {
				const re = {
					backgroundImage: `url(${this.bottomBgPicConfig.src})`,
					backgroundRepeat: '',
					backgroundSize: '',
					borderRadius: this.radiusConfig
				}
				if (this.bottomBgPicConfig.tabVal == 2) {
					re.backgroundSize = '100% 100%'
					re.backgroundRepeat = 'no-repeat'
				} else if (this.bottomBgPicConfig.tabVal == 1) {
					re.backgroundSize = '100%'
					re.backgroundRepeat = 'repeat'
				} else {
					re.backgroundSize = '100%'
					re.backgroundRepeat = 'no-repeat'
				}
				return re
			},
			// 组件内容
			compContentStyle2() {
				const re = {
					background: `linear-gradient(90deg, ${this.moduleColor[0]} 0%, ${this.moduleColor[1]} 100%)`,
				}
				return re
			},
			heightConfig() {
				return this.getAttr('heightConfig.val', 48)
			},
			imgConfig() {
				return this.getAttr('imgConfig.url', '')
			},
			tipConfig() {
				return this.getAttr('tipConfig.value', '')
			},
			buttonText1Config() {
				return this.getAttr('buttonText1Config.value', '')
			},
			buttonText2Config() {
				return this.getAttr('buttonText2Config.value', '')
			},
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		methods: {
			init() {

			},

		}
	}
</script>

<style lang="scss" scoped scoped>
	.comp-box {
		.comp-wrap {
			height: 100%;

			.content-box {
				height: 100%;
				display: flex;
				align-items: center;
				color: #6a4714;
				padding: 0 5px 0 15px;
				font-size: 13px;

				.title {
					display: flex;
					align-items: center;
					gap: 10px;
					flex: 1;
					font-weight: 600;
				}

				.button {
					color: #f0e1c9;
					margin-right: 11px;
					background: linear-gradient(90deg, #875916, #4a2d04);
					padding: 4px 15px;
					border-radius: 14px;
					white-space: nowrap;
					text-align: center;
					min-width: 50px;
				}
			}
		}
	}
</style>