<template>
	<view class="input-group">
		<u-input v-model="inputValue" :type="options.type || 'text'" :maxlength="options.maxlength || 2000"
			:clearable="options.clearable || true" :disabled="options.disabled || false"
			:showPassword="options.showPassword || false" :height="options.height || 40"
			:auto-height="options.autoHeight || true" :placeholder="tip" @input="handelInput" />
		<u-image :src="$util.img(suffixIcon)" v-if="suffixIcon" width="60" height="60" border-radius="10" />
	</view>
</template>

<script>
	export default {
		props: {
			options: {
				type: Object,
				default: () => {
					return {
						type: 'text',
						maxlength: 100,
						clearable: true,
						disabled: false,
						showPassword: false,
					}
				}
			},
			tip: {
				type: String,
				default: ''
			},
			value: {
				type: [String, Number],
				default: ''
			}
		},
		components: {

		},
		inject: {
			inputSuffixIcon: {
				default: ''
			}
		},
		data() {
			return {
				inputValue: ''
			};
		},
		computed: {
			suffixIcon() {
				if (this.inputSuffixIcon) {
					return this.inputSuffixIcon()
				} else {
					return ''
				}
			}
		},
		watch: {
			value: {
				handler(nv) {
					this.inputValue = nv
				},
				immediate: true
			}
		},
		created() {

		},
		mounted() {

		},
		methods: {
			handelInput() {
				this.$emit('input', this.inputValue)
			},
		},
	};
</script>

<style scoped lang="scss" scoped>
	.input-group {
		display: flex;
		align-items: center;
		width: 100%;
		height: 70rpx;
	}
</style>