<template>
	<view>
		<kss-page v-if="!errorNetwork" :styleConfig="styleConfig" :pageConfig="pageConfig">
			<template #comp>
				<product-win ref="product-win" :show.sync="showProductWin" :goods="goods" :sku="goodsSku"
					:spec-key="goodsSpecKey" :spec-value="goodsSpecValue" :selected-spec-value="selectedSpecValue"
					@sku="changeSku" @order-form="handelOrderFormChange" @spec="changeSpec" @combine="changeCombine"
					v-if="goods.id" />
			</template>
		</kss-page>
		<error-newwork v-else @retry="$u.throttle(reconnect, 500)" />

		<notice-win ref="notice-win" :data='goods.goods_notice' />
		<my-share ref="my_share" />
		<member-price-dialog ref="member-price-dialog" @level-up="handelLevelUp" />
		<bind-mobile ref="bind_mobile" @fetch-data="getUserInfo" />
	</view>
</template>

<script>
	import {
		mapGetters,
		mapMutations,
		mapActions
	} from 'vuex'

	import ErrorNewwork from '@/components/ErrorNetwork'
	import KssPage from '@/components/kss_diy_component/Page'
	import DiyPage from '@/mixins/diyPage.js'

	import ProductWin from './components/product-win'
	import NoticeWin from './components/notice-win'
	import MyShare from './components/my-share'
	import MemberPriceDialog from '@/components/MemberPriceDialog'
	import BindMobile from './components/BindMobile'

	import _ from 'lodash'

	export default {
		components: {
			'kss-page': KssPage,
			'error-newwork': ErrorNewwork,

			'product-win': ProductWin,
			'notice-win': NoticeWin,
			'my-share': MyShare,
			'member-price-dialog': MemberPriceDialog,

			'bind-mobile': BindMobile,
		},
		mixins: [DiyPage],
		provide() {
			return {
				getGoods: () => this.goods,
				canUpLevel: () => this.canUpLevel,
				getGoodsSku: () => this.goodsSku,
				getMerchant: () => this.merchant,
				getViewGoodsPrice: () => this.viewGoodsPrice,
				getCouponLabel: () => this.couponLabel,
				getSelectedSpecValue: () => this.selectedSpecValue,
				getShowProductWin: () => this.showProductWin,

				updateFavorite: this.collect,
				showMemberPrice: this.showMemberPrice,
				handelShare: this.handelShare,
				chooseProduct: this.chooseProduct,
				joinCart: this.handelJoinCart,
				submit: this.submit,
				kefu: this.kefu
			}
		},
		data() {
			return {
				// 商品详情请求数据
				queryForm: {
					id: '',
					sku_id: '',
					spec_id: '',
				},
				canUpLevel: false,
				goods: {
					goods_imgs: [],
					// goods_price:'0'
				},
				goodsSku: [],
				kefulink: '',
				merchant: {},
				couponLabel: [],

				viewGoodsPrice: false, //显示隐藏会员价
				showProductWin: false,
				// 卡密，手工下单数据
				orderForm: {
					goods_id: '', // 商品ID
					batch_tpl: {}, // (手工订单需要)批量下单模板json
					quantity: 1, // 下单数量	
					//2024-8-27卡密和手工支持多规格
					goods_spec_id: '', //规格id
					split_goods_ids: [], //选购商品ids
				},
				// 分享地址
				pageShareUrl: '',

				goodsSpecKey: [], // 商品规格key,规格键列表
				goodsSpecValue: {}, //商品规格value，以规格key组合为键的对象
				selectedSpecValue: {}, //选中规格商品
			}
		},
		computed: {
			...mapGetters(['deviceInfo']),
		},
		async onLoad(options) {
			if (options.pid)
				this.setPid(options.pid)
		},
		onLoad() {
			const {
				id,
				spec_id
			} = this.$Route.query
			if (!id) {
				this.$util.back()
				return
			}
			this.queryForm.id = id
			this.queryForm.spec_id = spec_id || ''
			this.loadData()
		},
		onShow() {

		},
		onHide() {

		},
		methods: {
			...mapMutations(['setPid']),
			...mapActions(['getUserInfo']),
			async loadData() {
				const {
					can_up_level,
					goods,
					goods_sku,
					merchant,
					kefulink,
					goods_spec_key,
					goods_spec_value,
					view_goods_price,
					coupon_label,
				} = await this.$u.api.categoods(this.queryForm)
				this.canUpLevel = can_up_level
				this.goods = goods
				this.goodsSku = goods_sku
				this.merchant = merchant
				this.kefulink = kefulink
				this.viewGoodsPrice = view_goods_price
				this.couponLabel = coupon_label

				this.goodsSpecKey = goods_spec_key
				this.goodsSpecValue = goods_spec_value
				if (goods_spec_key.length) {
					this.getSelectedSpecValue()
					this.orderForm.goods_spec_id = this.selectedSpecValue.id
				}

				this.orderForm.goods_id = goods.id
				await this.shareConfig()
				if (this.goods.goods_notice) {
					this.$refs['notice-win'].show()
				}
				this.$nextTick(() => {
					uni.setNavigationBarTitle({
						title: goods.goods_name + ' - ' + this.sysconfig.basic_system_name
					})
				})
			},
			getSelectedSpecValue() {
				// 优先判断url地址中存在规格
				if (this.queryForm.spec_id) {
					for (let i in this.goodsSpecValue) {
						if (this.goodsSpecValue[i].id == this.queryForm.spec_id) {
							this.selectedSpecValue = this.goodsSpecValue[i]
							break
						}
					}
				}
				// 默认选中规格赋值		
				// if (this.selectedSpecValue && !Object.keys(this.selectedSpecValue).length) {
				// 	const selectedIndex = this.goodsSpecKey.map(() => {
				// 		return 0
				// 	})
				// 	let arr = []
				// 	selectedIndex.forEach((item, index) => {
				// 		if (item == -1) arr.push('')
				// 		else arr.push(this.goodsSpecKey[index].attr_values[item].name)
				// 	})
				// 	if (arr.join(',') in this.goodsSpecValue)
				// 		this.selectedSpecValue = this.goodsSpecValue[arr.join(',')]
				// 	else
				// 		this.selectedSpecValue = {}
				// }
			},
			chooseProduct() {
				this.showProductWin = true
			},
			kefu() {
				this.$util.on(this.kefulink)
			},
			async collect() {
				const {
					favorite_num
				} = await this.$u.api.savefavorite({
					goods_id: this.goods.id
				})
				this.goods.is_favorite = !this.goods.is_favorite
				this.goods.favorite_num = favorite_num
			},
			changeSku(e) {
				this.orderForm = this.$options.data().orderForm
				this.queryForm = Object.assign(this.queryForm, e)
				this.pageShareUrl = this.$options.data().pageShareUrl

				this.goodsSpecKey = this.$options.data().goodsSpecKey
				this.goodsSpecValue = this.$options.data().goodsSpecValue
				this.selectedSpecValue = this.$options.data().selectedSpecValue
				this.loadData().then(() => {
					this.$refs['product-win'].init()
				})
			},
			handelOrderFormChange(e) {
				this.orderForm = Object.assign(this.orderForm, e)
			},
			submit() {
				if (!this.userinfo.isLogin) {
					this.$Router.push({
						path: '/pages/user/login',
						query: {
							redirect: this.$Route.fullPath
						}
					})
					return
				}

				if (!this.showProductWin) {
					this.showProductWin = true
					return
				}

				if (this.goods.no_buy) {
					this.$util.msg('购买商品等级权限不足，请升级为更高等级')
					return
				}

				if (this.goods.goods_type == 1 || this.goods.goods_type == 2) {
					this.$refs['product-win'].checkForm().then(async () => {
						this.createOrder(this.orderForm)
						// window._agl && window._agl.push(['track', ['success', {
						// 	t: 6
						// }]])
						this.showProductWin = false
					}).catch(err => {
						console.log(err)
					})
				} else if (this.goods.goods_type == 3) {
					const path = `/pages/goods/create_order`
					const params = {
						id: this.goods.id,
						quantity: this.orderForm.quantity
					}
					if (this.goods.spec_type)
						params.spec_id = this.selectedSpecValue.id

					this.$util.on(this.$util.getRedirectUrl(path, params))
				}
			},
			async createOrder(orderForm) {
				try {
					const {
						order_sn
					} = await this.$u.api.createOrder(orderForm)
					// window._agl && window._agl.push(['track', ['success', {
					// 	t: 6
					// }]])
					this.$util.on(`/pages/goods/buy?ordersn=${order_sn}`)
				} catch (e) {
					console.log(e.data)
					if (e.data.msg == '请绑定手机后下单')
						this.$refs['bind_mobile'].show()
				}

			},
			handelShare() {
				const {
					id,
					goods_name,
					goods_price,
					face_value,
					default_level_price,
					goods_img
				} = this.goods
				this.$refs['my_share'].show({
					goods_id: id,
					goods_name: goods_name,
					face_value: face_value,
					goods_price: goods_price,
					default_level_price: default_level_price,
					goods_img: goods_img
				})
			},
			handelGoodsImgClick(index) {
				uni.previewImage({
					urls: this.goods.goods_imgs.length > 0 ? this.goods.goods_imgs : [this.goods.goods_img],
					current: index
				})
			},
			async shareConfig() {
				const {
					page_share_url,
					sharewxgzhConfig
				} = await this.$u.api.shareConfig(this.queryForm)
				this.pageShareUrl = page_share_url
				//#ifdef H5		
				if (this.pageShareUrl.indexOf('&pid=') === -1) {
					this.pageShareUrl = this.pageShareUrl + '&pid=' + this.userinfo.id;
				}
				if (this.$util.browserType('weixin')) {
					if (!Array.isArray(sharewxgzhConfig)) {
						this.wxShare(sharewxgzhConfig, this.getWxShareData())
					}
				}
				//#endif
			},
			async wxShare(res, options) {
				// console.log(options)
				//配置
				jWeixin.config({
					debug: res.debug ? true : false, //根据服务端来控制是否开启调试模式
					appId: res.appId,
					timestamp: res.timestamp,
					nonceStr: res.nonceStr,
					signature: res.signature,
					jsApiList: res.jsApiList,
				});
				//分享的触发动作必须写再ready里面
				jWeixin.ready(() => {
					//配置分享数据
					let shareData = {
						title: options.title || "", //分享的标题
						desc: options.desc || "", //分享的描述
						link: options.linkUrl, //分享的链接
						imgUrl: options.imgUrl || "", //分享的图片链接
						success(response) {
							//配置成功之后的回调（并不是分享成功之后的回调，这个地方是个坑，要注意下）
							// console.log('user shared');
						},
					};
					jWeixin.updateAppMessageShareData(shareData)
					jWeixin.updateTimelineShareData(shareData)
					jWeixin.onMenuShareAppMessage(shareData)
					jWeixin.onMenuShareTimeline(shareData)
				})
			},
			getWxShareData() {

				return {
					title: this.goods.goods_name,
					desc: `现价:${this.goods.goods_price} \r\n原价:${this.goods.face_value}`,
					linkUrl: this.pageShareUrl,
					imgUrl: this.goods.goods_img,
				}
			},
			// 规格改变回调
			changeSpec(e) {
				if (!_.isEmpty(e)) {
					const {
						stock_num,
						goods_img,
						face_value,
						goods_price,
					} = e

					this.selectedSpecValue = e
					this.goods.goods_img = goods_img
					this.goods.goods_price = goods_price
					this.goods.stock_num = stock_num
					this.goods.face_value = face_value
				}
			},
			// 加入购物车点击
			handelJoinCart() {
				if (!this.showProductWin) {
					this.showProductWin = true
					return
				}
				if (this.goods.goods_type == 1) {
					this.$u.throttle(async () => {
						await this.$u.api.goodsCartSave({
							batch_tpl: this.orderForm.batch_tpl,
							goods_id: this.orderForm.goods_id,
							goods_sku_id: this.selectedSpecValue.id,
							num: this.orderForm.quantity,
						})
						this.$util.msg('添加购物车成功')
					}, 1000)
				} else if (this.goods.goods_type == 2) {
					this.$refs['product-win'].checkForm().then(async () => {
						this.$u.throttle(async () => {
							await this.$u.api.goodsCartSave({
								goods_id: this.orderForm.goods_id,
								batch_tpl: this.orderForm.batch_tpl,
								goods_sku_id: this.selectedSpecValue.id,
								num: this.orderForm.quantity,
							})
							this.$util.msg('添加购物车成功')
						}, 1000)
					}).catch(err => {
						console.log(err)
					})
					this.$util.msg('添加购物车成功')
				} else if (this.goods.goods_type == 3) {
					this.$u.throttle(async () => {
						await this.$u.api.goodsCartSave({
							batch_tpl: this.orderForm.batch_tpl,
							goods_id: this.orderForm.goods_id,
							goods_sku_id: this.selectedSpecValue.id,
							num: this.orderForm.quantity,
						})
						this.$util.msg('添加购物车成功')
					}, 1000)
				}
			},
			// 弹框选择下单模板回调
			async handelChooseAttach({
				batch_tpl,
				mark
			}) {
				await this.$u.api.goodsCartSave({
					goods_id: this.goods.id,
					num: this.orderForm.quantity,
					mark,
					batch_tpl
				})
				this.$message.success('加入购物成功')
			},
			showMemberPrice() {
				this.$refs['member-price-dialog'].show({
					goods_id: this.goods.id,
					goods_sku_id: this.selectedSpecValue.id,
					canUpLevel: this.canUpLevel,
				})
			},
			handelLevelUp(e) {
				this.$Router.push({
					path: '/pages/ucenter_sub/upgrade/settle',
					query: {
						level_id: e.level_id,
					}
				})
			},
			changeCombine(e) {
				if (!_.isEmpty(e)) {
					this.orderForm.split_goods_ids = e
				}
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	::v-deep {
		.scroll-y {
			height: calc(var(--vh) * 100 - var(--status-bar-height));
		}
	}
</style>