import {
	mapActions,
	mapGetters,
	mapMutations
} from 'vuex'

export default {
	data() {
		return {
			renderTime: 0, // 渲染时间

			pageConfig: {}, // 页面配置数据(除去动态组件数据,考虑已经有styleConfig来传递动态组件数据，这里仅放页面的配置数据)
			styleConfig: [],
			errorNetwork: false, // 是否断网
		};
	},
	computed: {
		...mapGetters(['defaultTheme']),
		isDevEnv() {
			if (process.env.NODE_ENV === 'development') {
				// 开发环境
				return true
			} else if (process.env.NODE_ENV === 'production') {
				// 生产环境
				return false
			}
		},
	},
	provide() {
		return {
			injectPageConfig: () => {
				return this.pageConfig
			}
		}
	},
	watch: {

	},
	options: {
		styleIsolation: 'shared'
	},
	onLoad() {

	},
	async onShow() {
		// 获取页面数据
		await this.loadDiyData()
		this.$nextTick(() => {
			uni.$emit(`page-show-${this.pageConfig.id}`)
		})
	},
	onHide() {
		uni.$emit(`page-hide-${this.pageConfig.id}`)
	},
	onReady() {
		// 页面准备好后记录当前时间
		if (this.isDevEnv) {
			const startTime = Date.now()
			setTimeout(() => {
				// 假设300ms后页面算是渲染完成，可以自定义这个时间
				const endTime = Date.now()
				this.renderTime = endTime - startTime; // 计算渲染时间
				console.log(`页面渲染速度：${this.renderTime}ms`)
			}, 300)
		}
	},
	methods: {
		...mapActions(['getPageData']),
		...mapMutations(['setPageTheme']),
		async loadDiyData() {
			try {
				const {
					needReload,
					diyData
				} = await this.getPageData(this.$Route.path)
				this.setDiyData(diyData)
			} catch (err) {
				uni.showToast({
					title: '请检查网络连接',
					icon: 'none',
					duration: 2000
				})
				this.errorNetwork = true
			}
		},
		setDiyData(data) {
			this.errorNetwork = false
			// 设置页面标题
			this.setTitle(data.title)
			// 设置主题
			this.setTheme(data.is_theme_config, data.theme_config)
			// 获取页面配置数据
			let copy_data = this.$u.deepClone(data)
			Reflect.deleteProperty(copy_data, 'value')
			this.pageConfig = copy_data
			// 整理动态组件数据
			let temp = []
			let lastArr = this.objToArr(data.value);
			lastArr.forEach((item, index, arr) => {
				// 将pageFoot组件从组件列表里面
				if (item.name != 'pageFoot' && item.isHide != '1') {
					temp.push(item)
				}
			})

			function sortNumber(a, b) {
				return a.timestamp - b.timestamp;
			}
			temp.sort(sortNumber)

			this.styleConfig = temp
		},
		// 对象转数组
		objToArr(data) {
			let obj = Object.keys(data).sort();
			let m = obj.map(key => data[key]);
			return m;
		},
		// 页面主题色
		setTheme(is_theme_config, theme_config) {
			let viewColor = ''
			if (is_theme_config) {
				const {
					theme,
					priceColor,
					bntColor,
					gradient,
					minorColor,
					minorColorT
				} = theme_config
				viewColor =
					`--view-theme: ${theme};--view-priceColor:${priceColor};--view-minorColor:${minorColor};--view-minorColorT:${minorColorT};--view-bntColor:${bntColor};--view-gradient:${gradient}`
			} else {
				const {
					theme,
					priceColor,
					bntColor,
					gradient,
					minorColor,
					minorColorT
				} = this.defaultTheme
				viewColor =
					`--view-theme: ${theme};--view-priceColor:${priceColor};--view-minorColor:${minorColor};--view-minorColorT:${minorColorT};--view-bntColor:${bntColor};--view-gradient:${gradient}`
			}
			// uni.setStorageSync('viewColor', viewColor)
			// uni.$emit('ok', viewColor)
			this.setPageTheme(viewColor)
		},
		reconnect() {
			this.loadDiyData()
		},
		setTitle(title) {
			if (this.$Route.path == '/pages/index/index')
				uni.setNavigationBarTitle({
					title: this.sysconfig.basic_system_name
				})
			else
				uni.setNavigationBarTitle({
					title: title + ' - ' + this.sysconfig.basic_system_name
				})
		}
	}
};