<template>
	
	<view v-if="viewMinGoodsPrice && (type == 5 || type== 6)" :class="[badgeClassName]">
		<view class="wrap">
			最低价<template v-if="showPrice">￥{{ price2 }}</template>
		</view>
	</view>
	<view v-else-if="viewMinGoodsPrice" class="badge" :class="[badgeClassName]">
		<view class="wrap">
			最低价<template v-if="showPrice">￥{{ price2 }}</template>
		</view>
	</view>
</template>

<script>
	import {
		mapGetters
	} from 'vuex'
	import _ from 'lodash'

	export default {
		components: {},
		props: {
			// 展示样式
			type: {
				type: Number,
				default: 0
			},
			price1: {
				type: [Number, String],
				default: 0
			},
			price2: {
				type: [Number, String],
				default: 0
			}
		},
		data() {
			return {}
		},
		computed: {
			...mapGetters(['sysconfig']),
			viewMinGoodsPrice() {
				return this.sysconfig.goods.view_min_goods_price
			},
			badgeClassName() {
				return `badge-style-${this.type}`
			},
			showPrice() {
				return _.isEqual(this.price1 - 0, this.price2 - 0) ? false : true
			}
		},
		watch: {},
		mounted() {},
		methods: {}
	}
</script>

<style scoped lang="scss" scoped>
	.badge {
		position: absolute;
		top: 0rpx;
		right: 0;
		transform: translateY(-50%) translateX(100%);
		white-space: nowrap;
		font-size: 24rpx;
	}

	.badge-style-0 {
		border-radius: 20rpx;
		border-bottom-left-radius: 0;
		background-image: linear-gradient(90deg, #fe8a56, #ff504b);
		color: #fff;
		padding: 0 10rpx;
	}

	.badge-style-1 {
		z-index: 10;
		background-color: #ff5436;
		background-image: radial-gradient(top left,
				#ff9719 0,
				#ff5535 60%,
				#ff5535 100%);
		color: #fff;
		font-size: 24rpx;
		line-height: 30rpx;
		border-radius: 4rpx 4rpx 4rpx 0;
		padding: 2rpx 12rpx;
		font-style: normal;

		&::after {
			content: '';
			position: absolute;
			bottom: -6rpx;
			left: 0;
			border-width: 4rpx;
			border-style: solid dashed dashed solid;
			border-color: #ff5436 transparent transparent #ff5436;
		}
	}

	.badge-style-2 {
		width: fit-content;
		transform: translateY(-120%) translateX(-50%);
		left: 50%;
		z-index: 10;
		background-color: #ff5436;
		background-image: radial-gradient(top left,
				#ff9719 0,
				#ff5535 60%,
				#ff5535 100%);
		color: #fff;
		font-size: 24rpx;
		line-height: 30rpx;
		border-radius: 4rpx 4rpx 4rpx 0;
		padding: 4rpx 12rpx;
		font-style: normal;

		&::after {
			content: '';
			position: absolute;
			bottom: -24rpx;
			left: 50%;
			transform: translateX(-50%);
			width: 20rpx;
			height: 20rpx;
			background-color: #ff5436;
			clip-path: polygon(0 0, 100% 0, 50% 100%);
		}
	}

	.badge-style-3 {
		top: 50%;
		right: -16rpx;
		width: fit-content;
		transform: translateY(-50%) translateX(100%);
		z-index: 10;
		background-color: #ff5436;
		background-image: radial-gradient(top left,
				#ff9719 0,
				#ff5535 60%,
				#ff5535 100%);
		color: #fff;
		font-size: 24rpx;
		line-height: 30rpx;
		border-radius: 4rpx 4rpx 4rpx 0;
		padding: 4rpx 12rpx;
		font-style: normal;

		&::after {
			content: '';
			position: absolute;
			transform: translateY(-50%);
			width: 20rpx;
			height: 20rpx;
			background-color: #ff5436;
			clip-path: polygon(0 50%, 100% 0, 100% 100%);
			left: -14rpx;
			top: 50%;
		}
	}

	.badge-style-4 {
		top: 50%;
		right: -16rpx;
		width: fit-content;
		transform: translateY(-50%) translateX(100%);
		z-index: 10;
		background-color: #ff5436;
		background-image: radial-gradient(top left,
				#ff9719 0,
				#ff5535 60%,
				#ff5535 100%);
		color: #fff;
		font-size: 24rpx;
		line-height: 30rpx;
		border-radius: 8rpx;
		padding: 4rpx 12rpx;
		font-style: normal;
	}
	
	.badge-style-5 {
		width: fit-content;
		// transform: translateY(-50%) translateX(100%);
		z-index: 10;
		background-color: #ff5436;
		background-image: radial-gradient(top left,
				#ff9719 0,
				#ff5535 60%,
				#ff5535 100%);
		color: #fff;
		font-size: 24rpx;
		line-height: 30rpx;
		border-radius: 8rpx;
		padding: 4rpx 12rpx;
		font-style: normal;
	}
	.badge-style-6 {
		display: flex;
		align-items: center;
		justify-content: center;
		font-size: 18rpx;
		color: #fff;
		background-color: #f84d43;
		height: 48rpx;
		padding: 0 10rpx;
		box-sizing: border-box;
		border-radius: 0 0 20rpx 20rpx;
	}
</style>