<template>
	<view class="comp-box" :style="[compStyle]" v-if="token" @click="handlelogout">
		<view class="comp-wrap" :style="[compWrapStyle]">
			<view class="content-box" :style="{color:buttonTextColor}">
				{{ buttonText }}
			</view>
		</view>
	</view>
</template>

<script>
	import CompMixin from '../mixins/comp.js'
	import {
		mapActions
	} from 'vuex'

	export default {
		name: 'VipBanner',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {

			}
		},
		options: {
			styleIsolation: 'shared'
		},
		computed: {
			buttonTextColor() {
				return this.getAttr('buttonText.color', '')
			},
			buttonText() {
				return this.getAttr('buttonText.value', '')
			},
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		methods: {
			...mapActions(['logout']),
			init() {

			},
			async handlelogout() {
				await this.$u.api.logout()
				await this.logout()

				uni.redirectTo({
					url: '/pages/user/login'
				})
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	.comp-box {
		.comp-wrap {
			padding: 32rpx 40rpx;
			border-radius: 20rpx;
		}

		.content-box {
			text-align: center;
			min-width: 160rpx;
		}
	}
</style>