<template>
	<u-popup v-model="popupShow" mode="center" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.1)'}"
		:border-radius="20" width="700rpx" :closeable="true" @open="open" @close="close">
		<view class="popup-content">
			<view class="curr-price">
				<view class="price-box">
					<view class="price">¥ {{ currPrice.goods_price }}</view>
					<view class="name">当前{{ currPrice.name }}购买价</view>
				</view>
			</view>
			<view class="price-list">
				<view v-for="(item, index) in priceList" :key="index" class="price-item"
					:class="{ disabled: item.is_click != 1 }" @click="levelUp(item)">
					<view class="left">¥{{ item.goods_price }}</view>
					<view class="name">{{ item.name }}购买价</view>
				</view>
			</view>
		</view>
		<view class="popup-footer" v-if="canUpLevel">
			<u-button size="medium" type="primary" @click="defaultLevelUp"> 提升等级 </u-button>
		</view>
	</u-popup>
</template>

<script>
	import _ from 'lodash'

	export default {
		components: {},
		data() {
			return {
				queryForm: {
					goods_id: '',
					goods_sku_id: ''
				},
				priceList: [],
				currPrice: {},
				canUpLevel: false,

				title: '',
				popupShow: false,
				loading: false
			}
		},
		computed: {},
		created() {},
		methods: {
			async loadData() {
				const data = await this.$u.api.goodsMemberPriceList(this.queryForm)
				console.log(data);
				this.priceList = data
				this.currPrice = _.find(data, {
					is_this: 1
				})
			},
			show(e) {
				this.canUpLevel = e.canUpLevel || false
				this.queryForm = Object.assign(this.queryForm, e)
				this.title = '会员等级价格明细'
				this.popupShow = true

			},
			open() {
				this.loadData()
			},
			close() {
				this.queryForm = this.$options.data().queryForm
				this.priceList = []
				this.currPrice = this.$options.data().currPrice
			},
			levelUp(item) {
				if (item.is_click != 1) return
				this.$emit('level-up', item)
				this.popupShow = false
			},
			defaultLevelUp() {
				if (this.priceList.length) {
					this.$emit('level-up', this.priceList[0])
					this.popupShow = false
				}
			}
		}
	}
</script>
<style lang="scss" scoped scoped>
	.popup-content {
		padding: 40rpx;
	}

	.curr-price {
		.price-box {
			width: 360rpx;
			margin: 0 auto;
			border: 4rpx solid #ee7236;
			line-height: 1;
			text-align: center;
			border-radius: 12rpx;
			padding: 20rpx 0;

			.price {
				color: #fe6247;
				font-weight: bolder;
				font-size: 40rpx;
			}

			.name {
				font-size: 26rpx;
				margin-top: 20rpx;
			}
		}
	}

	.price-list {
		display: flex;
		flex-direction: column;
		gap: 20rpx;
		margin-top: 40rpx;

		.price-item {
			display: flex;
			justify-content: space-between;
			align-items: center;
			color: #ed6625;
			background-color: #fff4f0;
			height: 80rpx;
			line-height: 1;
			padding: 0 40rpx;
			border-radius: 12rpx;

			.name {
				font-size: 26rpx;
				cursor: pointer;
				user-select: none;
			}
		}

		.disabled {
			.name {
				color: gray;
				cursor: not-allowed;
			}
		}
	}

	.popup-footer {
		display: flex;
		justify-content: center;
		padding-bottom: 40rpx;
	}
</style>