<template>
	<view id="product-window">
		<view class="product-window" :class="{on:show}">
			<view class="iconfont icon-guanbi1" @click="close"></view>
			<view class="textpic acea-row">
				<view class="pictrue">
					<image :src="$util.img(goodsData.goods_img)">
					</image>
					<view class="icon acea-row row-center-wrapper" @click="preview">
						<text class="iconfont icon-wxbsousuotuiguang"></text>
					</view>
				</view>
				<view class="right">
					<view class="line2">
						{{goodsData.goods_name}}
					</view>
					<view class="sku-code" @click="copyLink(goodsData.spec_value.code || '')"
						v-if="goodsData.spec_type">规格编码：{{goodsData.spec_value.code}}</view>
					<view class="price-box">
						<view class="actual-price">
							<text class="title">共实付</text>
							<view class="price-num">
								<text class="symbol">￥</text>
								<text class="num">{{totalGoodsPriceData.coupon_price}}</text>
							</view>
						</view>
						<template v-if="totalGoodsPriceData.coupon_id">
							<view class="sale-price">
								<text class="title">共减</text>
								<view class="price-num">
									<text class="symbol">￥</text>
									<text class="num">{{totalGoodsPriceData.received_price}}</text>
								</view>
							</view>
						</template>
					</view>
				</view>
			</view>
			<view class="rollTop">
				<!-- 选购商品 -->
				<combine-goods v-if="isCombineGoods" :source="goods.split_combine_goods_list"
					@change="onCombineGoodsChange" />
				<!-- 商品组合 -->
				<view class="productWinList" v-if="sku.length">
					<view class="item" v-for="item1,index1 in sku" :key="index1">
						<view class="title">{{item1.name}}</view>
						<view class="listn acea-row row-middle">
							<view class="itemn" :class="{on:item2.goods_id == goods.id}"
								v-for="item2,index2 in item1.skuList" :key="index2"
								@click="skuClick(item1.id,item2.goods_id)">{{item2.name}}</view>
						</view>
					</view>
				</view>
				<!-- 多规格 -->
				<view class="goodsSpec" v-if="specKey.length>0">
					<goods-spec :spec-key="specKey" :spec-value="specValue" :selected-spec-value="selectedSpecValue"
						@change="changeSpec" />
				</view>
				<!-- 下单模板 -->
				<view class="productTpl" v-show="goods.attach && goods.attach.length">
					<u-radio-group v-model="showBatchOrder" v-if="goods.is_batch == 1">
						<u-radio :name="0">
							单个购买
						</u-radio>
						<u-radio :name="1">
							批量下单
						</u-radio>
					</u-radio-group>
					<goods-attach ref="attach" :attach="goods.attach" :show-batch-order="showBatchOrder"
						@attach-value="getAttachValue" />
				</view>
				<!-- 下单数量 -->
				<view class="cart acea-row row-between-wrapper">
					<view class="title">数量</view>
					<view class="carnum acea-row row-left" v-if="goods.num_type == 1">
						<u-number-box v-model="quantity" @change="quantityChange" :min="goods.start_count"
							:max="goods.end_count"></u-number-box>
					</view>
					<view class="acea-row row-left" style="flex:1;" v-else-if="goods.num_type == 2">
						<view @click="showNumPicker=true" style="display:flex;flex:0%;justify-content: flex-end;">
							<text style="margin-right: 10rpx;">{{quantity}}</text>
							<u-icon name="arrow-right" color="#ccc"></u-icon>
						</view>
					</view>
				</view>
			</view>
		</view>
		<view class="mask" v-show="show" :class="{'mask-on':show}" @click="close" @touchmove.stop.prevent></view>
		<u-select v-model="showNumPicker" mode="single-column" :list="numList" @confirm="quantityChange"
			:safe-area-inset-bottom="true"></u-select>
	</view>
</template>

<script>
	import Attach from '@/components/ChooseOrderTplDialog/attach'
	import Spec from './spec'
	import _ from 'lodash'
	import CombineGoods from './combine-goods'

	export default {
		components: {
			'goods-attach': Attach,
			'goods-spec': Spec,
			'combine-goods': CombineGoods
		},
		props: {
			show: {
				type: Boolean,
				default: false,
			},
			goods: {
				type: Object,
				default: () => {}
			},
			sku: {
				type: Array,
				default: () => []
			},
			specKey: {
				type: Array,
				default: () => []
			},
			specValue: {
				type: Object,
				default: () => {
					return {}
				}
			},
			selectedSpecValue: {
				type: Object,
				default: () => {
					return {}
				}
			},
		},
		data() {
			return {
				quantity: 1,
				showBatchOrder: 0, //显示批量下单

				showNumPicker: false,
				numList: [],

				priceForm: {
					quantity: 0,
					goods_id: '',
					goods_spec_id: '',
				},

				totalGoodsPriceData: {},
			}
		},
		computed: {
			goodsData() {
				const re = {
					goods_name: this.goods.goods_name,
					goods_img: this.goods.goods_img,
					spec_type: this.goods.spec_type,
					goods_price: this.goods.goods_price,
					coupon_id: this.goods.coupon_id,
					coupon_price: this.goods.coupon_price,
					received_price: this.goods.received_price,
					spec_value: this.selectedSpecValue
				}
				if (this.specKey.length) {
					if (Object.keys(this.selectedSpecValue).length) {
						const {
							goods_img,
							goods_price,
						} = this.selectedSpecValue
						re.goods_img = goods_img
						re.goods_price = goods_price
					}
				}

				return re
			},
			isCombineGoods() {
				return this.goods.split_combine_goods_list ?
					true : false
			},
		},
		watch: {},
		onReady() {},
		mounted() {
			this.init()
		},
		methods: {
			init() {
				const {
					num_type,
					num_count,
					start_count
				} = this.goods

				if (num_type == 1) {
					if (start_count > this.quantity) {
						this.quantity = start_count

						this.$emit('order-form', {
							quantity: this.quantity
						})
					}
				} else if (num_type == 2) {
					this.numList = this.parseNumCount(num_count)
					if (this.numList.length) {
						this.quantity = this.numList[0].value
						this.$emit('order-form', {
							quantity: this.quantity
						})
					}
				}

				if (this.selectedSpecValue) {
					this.priceForm.goods_spec_id = this.selectedSpecValue.id
				}
				// 刷新商品价格
				this.fetchGoodsPrice()
			},
			copyLink(text) {

				if (text) {

					uni.setClipboardData({
						data: text,
						success: function() {
							uni.showToast({
								title: '复制成功',
								mask: false,
								duration: 1500,
								icon: 'none'
							});
						}
					})
				}

			},
			checkForm() {
				return new Promise(async (resolve, reject) => {
					try {
						await this.$refs['attach'].checkForm()
						resolve('表单验证通过')
					} catch (e) {
						reject('表单验证失败', e)
					}
				})
			},
			close() {
				// this.$refs['uForm'].resetFields()
				this.show = false
				this.$emit('update:show', false)
			},
			preview() {
				uni.previewImage({
					urls: [this.goodsData.goods_img],
					current: this.goodsData.goods_img,
				});
			},
			skuClick(skuid, goods_id) {
				if (goods_id == this.goods.id)
					return
				// this.$refs['uForm'].resetFields()
				this.$emit('sku', {
					id: goods_id,
					sku_id: skuid
				})
			},
			quantityChange: _.throttle(function(e) {
				if (this.goods.num_type == 1) {
					this.$emit('order-form', {
						quantity: e.value
					})
				} else if (this.goods.num_type = 2) {
					this.quantity = e[0].value
					this.$emit('order-form', {
						quantity: e[0].value
					})
				}
				// 刷新商品价格
				this.fetchGoodsPrice()
			}, 500),
			// 获取商品价格
			async fetchGoodsPrice() {
				this.priceForm.quantity = this.quantity
				this.priceForm.goods_id = this.goods.id

				this.totalGoodsPriceData = await this.$u.api.getGoodsPrice(this.priceForm)
			},
			// 规格改变回调
			changeSpec(e) {
				if (!e)
					return
				console.log(e)
				this.$emit('spec', e)

				this.priceForm.goods_spec_id = e.id
				// 刷新商品价格
				this.fetchGoodsPrice()

			},
			// 返回商品模板的值
			getAttachValue({
				batch_tpl
			}) {
				this.$emit('order-form', {
					batch_tpl
				})
			},
			// 当num_type =2 时，使用select组件渲染下单数量，先解析下
			parseNumCount(str) {
				let arr = str.split(',').filter(Boolean)
				let re = []

				arr.forEach(item => {
					if (item.indexOf('-') != -1) {
						let tmp = item.split('-').map(Number)
						for (let i = tmp[0]; i <= tmp[1]; i++) {
							re.push({
								value: Number(i),
								label: i
							})
						}
					} else {
						re.push({
							value: Number(item),
							label: item
						})
					}
				})
				return re
			},
			// 选购商品改变回调
			onCombineGoodsChange(e) {
				if (e)
					this.$emit('combine', e)
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	.font-color {
		color: #FF504B;
	}

	.product-window {
		position: fixed;
		bottom: 0;
		width: 100%;
		left: 0;
		background-color: #fff;
		z-index: 100;
		border-radius: 16rpx 16rpx 0 0;
		transform: translate3d(0, 100%, 0);
		transition: all .3s cubic-bezier(.25, .5, .5, .9);
		padding-bottom: 104rpx;
		padding-bottom: calc(104rpx+ constant(safe-area-inset-bottom));
		padding-bottom: calc(104rpx + env(safe-area-inset-bottom));

		.icon-guanbi1 {
			position: absolute;
			right: 30rpx;
			top: 30rpx;
			font-size: 36rpx;
			color: #8a8a8a;
		}

		.textpic {
			padding: 0 30rpx;
			margin-top: 30rpx;
			margin-right: 30rpx;
			position: relative;

			.pictrue {
				width: 136rpx;
				height: 136rpx;
				position: relative;

				image {
					width: 100%;
					height: 100%;
					border-radius: 10rpx;
				}

				.icon {
					width: 30rpx;
					height: 30rpx;
					background-color: rgba(0, 0, 0, .4);
					border-radius: 4rpx;
					position: absolute;
					bottom: 8rpx;
					right: 8rpx;
					text-align: center;
					line-height: 22rpx;

					.iconfont {
						color: #fff;
						font-size: 20rpx;
					}
				}
			}

			.right {
				flex: 1;
				font-size: 32rpx;
				color: #202020;
				margin-left: 20rpx;
				display: flex;
				flex-direction: column;
				min-height: 136rpx;
				justify-content: space-between;

				.sku-code {
					white-space: nowrap;
					font-size: 24rpx;
					color: #999;
					margin-top: 6rpx;
				}

				.price-box {
					display: flex;
					align-items: baseline;
					font-size: 28rpx;

					.price-num {
						font-size: 38rpx;
						font-weight: 700;
						color: #ff504b;

						.symbol {
							font-size: 24rpx;
						}
					}

					.actual-price,
					.sale-price {
						display: flex;
						align-items: baseline;
					}

					.actual-price {
						color: #ff504b;

						.title {}

						.price-num {
							.symbol {
								font-size: 30rpx;
							}
						}
					}

					.sale-price {
						margin-left: 20rpx;

						.title {
							font-size: 24rpx;
							color: rgba(61, 61, 61, 1);
						}

						.price-num {
							font-size: 24rpx;
							color: rgba(61, 61, 61, 1);
						}
					}
				}

			}

		}

		.rollTop {
			max-height: 556rpx;
			overflow: auto;
			margin-top: 32rpx;

			.productWinList {
				.item {
					.title {
						font-size: 30rpx;
						color: #999;
						padding: 0 30rpx;
					}

					.listn {
						padding: 0 30rpx 0 16rpx;

						.itemn {
							border: 2rpx solid #f2f2f2;
							font-size: 26rpx;
							color: #282828;
							padding: 6rpx 34rpx;
							border-radius: 26rpx;
							margin: 20rpx 0 0 14rpx;
							background-color: #f2f2f2;
							word-break: break-all;
						}

						.on {
							color: #e0a558;
							background: transparent;
							border-color: #e0a558;
						}
					}
				}
			}

			.productTpl {
				margin-top: 36rpx;
				padding: 0 30rpx;
			}

			.cart {
				margin-top: 36rpx;
				padding: 0 30rpx 20rpx 30rpx;

				.title {
					font-size: 30rpx;
					color: #999;
				}

				.carnum {
					height: 56rpx;
				}
			}
		}
	}

	.on {
		transform: translateZ(0);
	}

	.mask-on {
		z-index: 99 !important;
	}
</style>