<template>
	<view>
		<u-popup v-model="popupShow" mode="bottom" :z-index="999" :custom-style="customStyle"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true" @close="close"
			@open="open">
			<view class="popup-title">
				<text>优惠</text>
			</view>
			<view class="popup-content">
				<scroll-view @touchmove.stop scroll-y class="scroll_content" :style="{height:'800rpx'}">
					<view class="detail-box">
						<view class="top">
							<view class="price-item">
								<text>￥{{detailData.coupon_price}}</text>
								<text>预估到手</text>
							</view>
						</view>
						<view class="border-bg">
							<view class="price-item">
								<text>￥{{detailData.goods_price}}</text>
								<text>商品原价</text>
							</view>
							<view class="heng"></view>
							<view class="price-item">
								<text>￥{{detailData.received_price}}</text>
								<text>优惠券</text>
							</view>
						</view>
					</view>
					<view class="coupon-box">
						<view class="title">可领取优惠券</view>
						<view class="coupon-list">
							<view class="coupon-item" v-for="(item,index) in couponList" :key="index">
								<view class="left">
									<view class="left-cup">
										<view class="price-num" v-if="item.coupon_type == 1">
											<text class="symbol">￥</text>
											<text class="num">1</text>
										</view>
										<view class="discount-num" v-else-if="item.coupon_type == 2">
											<text class="num">{{item.coupon_price}}</text>
											<text class="symbol">折</text>
										</view>
										<view class="condition">
											满{{item.use_min_price}}元可用
										</view>
									</view>
								</view>
								<view class="right">
									<view class="title">{{item.coupon_title}}</view>
									<view class="time-limit">
										<view class="limit-txt">{{item._type}}</view>
										<view class="btn bg-red get-btn" @click="getCoupon(item)"
											v-if="!item.is_receive">立即领取</view>
										<view class="btn bg-gray get-btn" @click="popupShow=false" v-else>已领取</view>
									</view>
								</view>
							</view>
						</view>
					</view>
				</scroll-view>
			</view>
			<view class="popup-footer">
				<view class="btn bg-red ok-btn" @click="handelOk">确 定</view>
			</view>
		</u-popup>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			customStyle: {
				type: Object,
				default: () => ({})
			},
		},
		data() {
			return {
				popupShow: false,

				detailData: {
					coupon_price: '',
					goods_price: '',
					received_price: '',
				},
				couponList: [],
			};
		},
		computed: {

		},
		watch: {

		},
		created() {

		},
		mounted() {

		},
		methods: {
			show({
				id // 商品id
			}) {
				this.popupShow = true
				this.fetchData(id)
			},
			close() {

			},
			open() {

			},
			handelOk() {
				this.popupShow = false
			},
			async getCoupon(row) {
				const data = await this.$u.api.couponReceive({
					id: row.id
				})
				this.$util.msg('领取成功')
			},
			async fetchData(id) {
				const {
					coupon_price,
					goods_price,
					received_price,
					coupon_list,
				} = await this.$u.api.goodsDiscountDetail({
					goods_id: id
				})
				this.detailData.coupon_price = coupon_price
				this.detailData.goods_price = goods_price
				this.detailData.received_price = received_price

				this.couponList = coupon_list
			}
		},
	};
</script>

<style scoped lang="scss" scoped>
	.popup-title {
		height: 100rpx;
		line-height: 100rpx;
		text-align: center;
		font-weight: bold;
		position: relative;
		background-color: #F5F5F5;
	}

	.popup-content {
		padding: 20rpx;
		background-color: #F5F5F5;
	}

	.popup-footer {
		padding: 20rpx;
		background-color: #F5F5F5;
	}

	.detail-box {
		.price-item {
			background: rgba(255, 33, 33, 0.1);
			width: 132rpx;
			height: 88rpx;
			display: flex;
			flex-direction: column;
			align-items: center;
			justify-content: center;
			color: rgba(255, 33, 33, 1);
			border-radius: 10rpx;
			font-size: 24rpx;
		}

		.top {
			display: flex;
			justify-content: center;
		}

		.border-bg {
			width: 100%;
			height: 65px;
			border: 1px solid rgba(255, 33, 33, 1);
			border-radius: 8px;
			background-size: 100%;
			position: relative;
			margin-top: 20rpx;
			display: flex;
			justify-content: center;
			align-items: center;

			&::before {
				content: "";
				position: absolute;
				top: -1px;
				left: 50%;
				width: 18rpx;
				height: 18rpx;
				border: 1px solid rgba(255, 33, 33, 1);
				border-bottom: 0;
				border-right: 0;
				background-color: #F5F5F5;
				box-sizing: border-box;
				transform: rotate(45deg) translate(-50%);
			}

			.heng {
				width: 18rpx;
				height: 4rpx;
				background-color: rgba(255, 33, 33, 1);
				margin: 0 10rpx;
			}
		}
	}

	.coupon-box {
		margin-top: 40rpx;

		.title {
			font-size: 24rpx;
			padding: 20rpx 0;
		}

		.coupon-list {
			display: flex;
			flex-direction: column;
			gap: 20rpx;

			.coupon-item {
				display: flex;
				align-items: center;
				background-color: #fff;

				.left {
					width: 95px;
					height: 85px;
					border-radius: 12px 0 0 12px;
					background: linear-gradient(90deg, rgba(255, 33, 33, 1), rgba(255, 33, 33, .3));
					color: #fff;


					.left-cup {
						display: flex;
						flex-direction: column;
						justify-content: space-between;
						align-items: center;
						width: 100%;
						height: 100%;
						padding: 16px 0;
						position: relative;
						background: radial-gradient(circle at 0 42px, #f5f5f5 6px, transparent 0) top;

						&::after {
							content: "";
							position: absolute;
							top: 0;
							right: 0;
							width: 3px;
							height: 100%;
							background-image: radial-gradient(circle at 3px 6px, #fff 3px, transparent 3px);
							background-size: 3px 9px;
						}

						.price-num {
							font-size: 48rpx;
							font-weight: 700;

							.symbol {
								font-size: 24rpx;
							}
						}

						.discount-num {
							font-size: 48rpx;
							font-weight: 700;

							.symbol {
								font-size: 24rpx;

							}
						}
					}
				}

				.right {
					flex: 1;
					height: 100%;
					padding-right: 7px;
					padding-left: 12px;
					display: flex;
					justify-content: space-between;
					flex-direction: column;

					.title {
						display: flex;
						align-items: center;
						font-weight: 500;
						font-size: 30rpx;
					}

					.time-limit {
						display: flex;
						justify-content: space-between;
						align-items: center;

						.limit-txt {
							font-size: 20rpx;
							color: rgba(255, 33, 33, 1);
						}

						.get-btn {
							font-size: 24rpx;
							padding-top: 8rpx;
							padding-bottom: 8rpx;
							min-width: 140rpx;
						}
					}
				}
			}
		}
	}

	.popup-footer {
		.ok-btn {
			width: 100%;
			padding: 0;
			height: 72rpx;
			line-height: 72rpx;
			border-radius: 72rpx;
		}
	}
</style>