<template>
	<view class="comp-box" :style="[compStyle]">
		<view class="wrap" :style="[compContentStyle2]">
			<view class="category-box">
				<view class="category-list">
					<view class="category-item" :class="{on:categoryData.id == item.id}"
						v-for="item,index in shortCategoryList" :key="index" @click="change(item)">
						<u-image border-radius="50%" :src="img(item.img)" width="84" height="84" />
						<view class="t1 line1">{{item.name}}</view>
					</view>
					<template v-if="categoryList.length > 4">
						<view class="category-item more-item" v-if="showAll==false" @click="setShowAll(true)">
							<u-image :src="img('/statics/diy/common/components/CategoryChildList/100/icon_menu.svg')"
								width="84" height="84" />
							<view class="t1">查看更多</view>
						</view>
					</template>
				</view>
			</view>
		</view>
	</view>
</template>
<script>
	import CompMixin from '../mixins/comp.js'

	export default {
		components: {

		},
		name: 'CategoryChildList',
		props: {

		},
		mixins: [CompMixin],
		inject: ['getShowAll', 'setShowAll', 'getCategoryData', 'categoryChange'],
		data() {
			return {

			};
		},
		computed: {
			categoryList() {
				const arr = this.getCategoryData()
				return arr[0] ? arr[0].children : []
			},
			shortCategoryList() {
				if (!this.showAll)
					return this.categoryList.slice(0, 4)
				else
					return this.categoryList
			},
			categoryData() {
				const arr = this.getCategoryData()
				return arr[1] || {}
			},
			showAll() {
				return this.getShowAll()
			},
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		methods: {
			async init() {


			},
			change(item) {
				if (item.id == this.categoryData.id)
					return
				this.setShowAll(false)
				this.categoryChange(item, 1)
			},
		}
	}
</script>
<style lang="scss" scoped scoped>
	.category-box {
		.category-list {
			display: flex;
			flex-wrap: wrap;
			padding: 20rpx;
			gap: 20rpx;

			.category-item {
				cursor: pointer;
				display: flex;
				flex-direction: column;
				justify-content: center;
				align-items: center;
				gap: 10rpx;
				width: calc(20% - 20rpx);
				color: #9b9fa8;

				.t1 {
					align-self: stretch;
					text-align: center;
					font-size: 24rpx;
				}
			}

			.on {
				color: #fd4d20;
			}
		}
	}
</style>