<template>
	<view>
		<view style="height: 104rpx;"></view>
		<view class="fixed-box">
			<view class="comp-box" :style="[compStyle]">
				<view class="wrap" :style="[compContentStyle2]">
					<view class="buy-button">
						<view class="button-wrap">
							<view class="left-button">
								<view v-if="showInfoConfig.includes(0)" class="left-item"
									@click="$util.on('/pages/index/index')">
									<view class="iconfont icon-shouye-shouye"></view>
									<text class="txt">首页</text>
								</view>
								<view v-if="showInfoConfig.includes(1)" class="left-item" @click="kefu">
									<view class="iconfont icon-kefu"></view>
									<text class="txt">客服</text>
								</view>
								<view v-if="showInfoConfig.includes(2)" class="left-item"
									@click="$util.on('/pages/buyer/order')">
									<view class="iconfont icon-dingdan"></view>
									<text class="txt">订单</text>
								</view>
							</view>
							<view class="right">
								<BuyGrgoupButton :showCartButton="showCartButton" :goodsStatus="goodsData.status"
									:goodsStockNum="goodsData.stock_num" @joinCart="joinCart" @doBuy="doBuy" />
							</view>
						</view>
					</view>
				</view>
			</view>
		</view>

	</view>
</template>
<script>
	import CompMixin from '../mixins/comp.js'
	import _ from 'lodash'
	import BuyGrgoupButton from '@/components/kss_diy_component/comp/BuyGrgoupButton/index.vue'

	export default {
		components: {
			BuyGrgoupButton
		},
		name: 'BuyButton',
		props: {

		},
		mixins: [CompMixin],
		inject: ['getGoods', 'joinCart', 'submit', 'kefu', 'getSelectedSpecValue', 'getShowProductWin'],
		data() {
			return {

			};
		},
		computed: {
			showInfoConfig() {
				return this.getAttr('showInfoConfig.type', [])
			},
			showCartButton() {
				return !this.getAttr('showCartButton.tabVal', 0) ? true : false
			},
			goods() {
				return this.getGoods()
			},
			selectedSpecValue() {
				return this.getSelectedSpecValue()
			},
			showProductWin() {
				return this.getShowProductWin()
			},
			goodsData() {
				const re = {
					status: this.goods.status,
				}
				if (this.showProductWin) {
					if (this.goods.spec_type == 1 && Object.keys(this.selectedSpecValue).length) {
						re.stock_num = this.selectedSpecValue.stock_num
					} else {
						re.stock_num = this.goods.stock_num
					}
					return re
				} else {
					return {
						status: this.goods.status,
						stock_num: this.goods.stock_num
					}
				}
			}
		},
		watch: {},
		mounted() {
			this.init()
		},
		methods: {
			async init() {


			},
			doBuy: _.throttle(function() {
				this.submit()
			}, 1000)
		}
	}
</script>
<style lang="scss" scoped scoped>
	.fixed-box {
		position: fixed;
		z-index: 277;
		left: 0;
		right: 0;
		bottom: 0;
	}

	.comp-box {


		.wrap {
			display: flex;
			align-items: center;
			justify-content: center;
		}
	}

	.buy-button {
		position: relative;
		width: 100%;

		.button-wrap {
			display: flex;
			flex-wrap: nowrap;
			justify-content: space-between;
			align-items: center;
			border-top: 2rpx solid #f0f0f0;
			height: 104rpx;
			padding: 0 20rpx 0 30rpx;

			.left-button {
				flex: 1;
				display: flex;
				align-items: center;
				gap: 40rpx;

				.left-item {
					width: 40rpx;
					overflow: hidden;
					display: flex;
					flex-direction: column;
					justify-content: center;
					line-height: 1;
					gap: 10rpx;
					white-space: nowrap;

					&>.iconfont {
						font-size: 40rpx;
						color: #666;
					}

					&>.txt {
						font-size: 18rpx;
						color: #666;
					}
				}
			}

			.right {
				flex: 2;

			}
		}
	}
</style>