<script>
	import CompMixin from '../mixins/comp.js'

	export default {
		components: {

		},
		name: 'GoodsListV2',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {
				list: [],
				columnSize: 2 // 瀑布流的列数
			};
		},
		computed: {
			moduleBg() {
				return this.getAttr('moduleBg', {})
			},
			goodsBgColor() {
				return this.getAttr('goodsBgColor.value', '#fff')
			},
			goodsTitleColor() {
				return this.getAttr('goodsTitleColor.value', '#333')
			},
			showGoodsTitleTag() {
				return this.getAttr('showGoodsTitleTag.tabVal', 0) ? false : true
			},
			showGoodsPrice() {
				return this.getAttr('showGoodsPrice.tabVal', 0) ? false : true
			},
			goodsPriceColor() {
				return this.getAttr('showGoodsPrice.tabList[0].content[0].value', '#FF3C29')
			},
			showOldPrice() {
				return this.getAttr('showOldPrice.tabVal', 0) ? false : true
			},
			oldPriceTxt() {
				return this.getAttr('showOldPrice.tabList[0].content[0].value', '')
			},
			oldPriceColor() {
				return this.getAttr('showOldPrice.tabList[0].content[1].value', '#969696')
			},
			showSale() {
				return this.getAttr('showSale.tabVal', 0) ? false : true
			},
			saleTxt() {
				return this.getAttr('showSale.tabList[0].content[0].value', '')
			},
			saleTxtColor() {
				return this.getAttr('showSale.tabList[0].content[1].value', '#969696')
			},
			showJiaoBiao() {
				return this.getAttr('showJiaoBiao.tabVal', 0)
			},
			jiaoBiaoConfig() {
				return this.getAttr(`showJiaoBiao.tabList[${this.showJiaoBiao}]`, {})
			},
			compStyleV2() {
				const re = {
					marginTop: this.mbConfig,
					paddingTop: this.topConfig,
					paddingBottom: this.bottomConfig,
					paddingLeft: this.prConfig,
					paddingRight: this.prConfig,
				}
				if (this.moduleBg.tabVal == 0) {
					// 背景透明
					re.backgroundColor = 'transparent'
				} else if (this.moduleBg.tabVal == 1) {
					// 背景颜色
					re.backgroundColor = this.moduleBg.tabList[1].content[0].value
				} else if (this.moduleBg.tabVal == 2) {
					// 背景图片
					re.backgroundImage = `url(${this.moduleBg.tabList[2].content[0].value})`
					if (this.moduleBg.tabList[2].content[0].bg_size == 2) {
						re.backgroundSize = '100% 100%'
						re.backgroundRepeat = 'no-repeat'
					} else if (this.moduleBg.tabList[2].content[0].bg_size == 1) {
						re.backgroundSize = '100%'
						re.backgroundRepeat = 'repeat'
					} else {
						re.backgroundSize = '100%'
						re.backgroundRepeat = 'no-repeat'
					}
				}

				return re
			},
			radiusConfig() {
				const radius = this.getAttr('radiusConfig', {
					type: 0,
					valList: []
				})
				return radius.type ?
					`${radius.valList[0].val * 2}rpx ${radius.valList[1].val * 2}rpx ${radius.valList[2].val *2}rpx ${radius.valList[3].val * 2}rpx` :
					`${radius.val*2}rpx`
			},
			showType() {
				return this.getAttr('showType.tabVal', 0)
			},
			listType() {
				return this.getAttr('listType.tabVal', 0)
			},
			showAd() {
				return this.getAttr('showAd.tabVal', 0) ? false : true
			},
			adList() {
				return this.getAttr('adList.list', []).map(item => {
					const re = {}
					re.image = this.img(item.src)
					re.link = item.attrs[0].value.link
					return re
				})
			},
			// 商品样式
			goodsItemStyle() {
				const re = {}
				re.backgroundColor = this.goodsBgColor
				re.borderRadius = this.radiusConfig
				return re
			},
			chooseGoodsType() {
				return this.getAttr('chooseGoodsType.tabVal', 0)
			},
			goodsList() {
				return this.getAttr('goodsList.list')
			},
			classList() {
				return this.getAttr('classList.list')
			},
			goodsNumber() {
				return this.getAttr('goodsNumber.val', 10)
			},
			goodsSort() {
				return this.getAttr('goodsSort.tabVal', 0)
			},
			// 瀑布流列样式
			waterfallStyle() {
				const re = {
					'gridTemplateColumns': `repeat(${this.columnSize}, 1fr)`
				}
				return re
			},
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		methods: {
			async init() {
				let list = []
				if (this.chooseGoodsType === 0) {
					const queryForm = {
						count: 20,
						is_count: 0,
					}
					list = await this.$u.api.getDiyGoodsList(queryForm)
				} else if (this.chooseGoodsType == 1) {
					const queryForm = {
						is_count: 0,
					}
					queryForm.ids = this.goodsList.map(item => item.id)
					list = await this.$u.api.getDiyGoodsList(queryForm)
				} else if (this.chooseGoodsType == 2) {
					const queryForm = {
						is_count: 0,
						cid: this.classList.map(item => item.id),
						count: this.goodsNumber,
						sort_type: 1,
					}
					if (this.goodsSort == 0) {
						queryForm.sort_type = 1
					} else if (this.goodsSort == 1) {
						queryForm.sort_type = 5
					} else if (this.goodsSort == 2) {
						queryForm.sort_type = 3
					}
					list = await this.$u.api.getDiyGoodsList(queryForm)
				}
				// 瀑布流（二维数组）
				if (this.showType == 0 && this.listType == 4) {
					this.list = this.getWaterfallData(list)
				} else {
					this.list = list
				}
			},
			getWaterfallData(list = []) {
				let newList = []
				let size = this.columnSize

				let tempList = list.map(item => {
					return {
						_is_ad: false,
						data: item,
					}
				})
				if (this.showAd) {
					tempList.unshift({
						_is_ad: true,
						data: this.adList
					})
				}
				for (let i = 0; i < size; i++) {
					newList[i] = []
					for (let j = 0; j < tempList.length; j++) {
						let item = tempList[j * size + i]
						if (item)
							newList[i].push(item)
					}
				}
				return newList
			},
			handelAdClick(e) {
				const adItem = this.adList[e]
				this.$kss.JumpPath(adItem.link)
			},
			handelScroll(e) {},
		}
	}
</script>

<style lang="scss" scoped scoped>
