<template>
	<view class="comp_box" :style="[compStyle]">
		<view class="top"></view>
		<view class="header-box">
			<view class="search-input" @click="$kss.JumpPath('/pages/search/search')">
				<u-icon name="search" />
				<view class="input">{{ placeholders }}</view>
				<view class="search-btn">搜索</view>
			</view>
		</view>
		<view class="content">
			<!-- 轮播 -->
			<view class="swiperBg">
				<u-swiper :list="imgUrls" :height="360" :mode="mode" :autoplay="true" bg-color="none" mode="rect"
					:border-radius="borderRadio" img-mode="scaleToFill" @change="swiperChange"
					@click="swiperClick"></u-swiper>
			</view>
		</view>
	</view>
</template>

<script>
	import CompMixin from '../mixins/comp.js'
	export default {
		name: 'SZBannerSearch',
		props: {
			isScrolled: {
				type: Boolean,
				default: false
			},
		},
		mixins: [CompMixin],
		data() {
			return {
				bgPic: '',
			}
		},
		watch: {

		},
		computed: {
			mpHeaderStyle() {
				let style = {}
				if (this.isScrolled && this.dataConfig.searchConfig.tabVal) {
					style.background = `linear-gradient(90deg, #FFFFFF 50%, #FFFFFF 100%)`
					style.position = `fixed`
				}
				return style;
			},
			inputStyle() {
				let style = {};
				if (this.isScrolled && this.dataConfig.searchConfig.tabVal) {
					style.background = `#F5F5F5`;
					style.color = `#BBBBBB`;
				}
				return style;
			},
			// 图片轮播数据
			imgUrls() {
				return this.dataConfig.swiperConfig.list.map(item => {
					return {
						image: this.$util.img(item.img || ''),
						title: item.info[0].value,
						url: item.info[1].value
					}
				})
			},
			// 轮播模式
			mode() {
				let docConfig = this.dataConfig.docConfig || {}
				if (docConfig.tabVal === 0)
					return 'rect'
				else if (docConfig.tabVal === 1)
					return 'dot'
				else if (docConfig.tabVal === 2)
					return 'number'
				else if (docConfig.tabVal === 3)
					return 'none'
				else
					return 'none'
			},
			// 指示器位置
			indicatorPos() {
				let docPosition = this.dataConfig.docPosition || {}
				if (docPosition.tabVal === 0)
					return 'topLeft'
				else if (docPosition.tabVal === 1)
					return 'topCenter'
				else if (docPosition.tabVal === 2)
					return 'topRight'
				else if (docPosition.tabVal === 3)
					return 'bottomLeft'
				else if (docPosition.tabVal === 4)
					return 'bottomCenter'
				else if (docPosition.tabVal === 5)
					return 'bottomRight'
				else
					return 'bottomCenter'
			},
			// 开启3D
			effect3d() {
				let styleConfig = this.dataConfig.styleConfig || {}
				return styleConfig.tabVal == 0 ? false : true
			},
			// 圆角
			borderRadio() {
				let filletImg = this.dataConfig.filletImg || {}
				if (filletImg.type == 0) {
					return filletImg.val * 2
				} else
					return 8
			},
			placeholders() {
				return this.getAttr('inputConfig.value', '')
			},
		},
		mounted() {
			this.init()
		},
		methods: {
			init() {
				const {
					swiperConfig
				} = this.dataConfig
				this.bgPic = swiperConfig.list.length ? swiperConfig.list[0].img : ''
			},
			swiperChange(index) {
				this.bgPic = this.dataConfig.swiperConfig.list.length ? this.dataConfig.swiperConfig.list[index].img : ''
			},
			swiperClick(index) {
				this.$kss.JumpPath(this.imgUrls[index].url)
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	.comp_box {
		position: relative;
		overflow: hidden;

		.top {
			position: absolute;
			z-index: 0;
			top: 0%;
			left: 0;
			height: 340rpx;
			width: 100%;
			background: linear-gradient(180deg, #fc3510 0%, #fd934c 60%, #fff 100%);

			&::after {
				content: '';
				position: absolute;
				display: block;
				top: 0;
				left: 0;
				width: 50%;
				height: 70%;
				background: linear-gradient(133deg, #fd633b 0%, #fd6931 100%);
				border-radius: 0 0 100%;
			}
		}

		.header-box {
			position: absolute;
			top: 0;
			left: 50%;
			transform: translate(-50%);
			height: 110rpx;
			display: flex;
			align-items: center;
			justify-content: center;
			width: 100%;
			background: linear-gradient(180deg, #fc3510 0%, #fd6c33 100%);
			z-index: 1;
			overflow: hidden;
			padding: 0 10px;

			.search-input {
				z-index: 99;
				display: flex;
				align-items: center;
				justify-content: space-between;
				height: 68rpx;
				background: #ffffff;
				border-radius: 8rpx;
				padding: 0 8rpx 0 16rpx;
				font-size: 28rpx;
				color: #9b9fa8;
				flex: 1;
				width: 100%;

				.el-icon-search {}

				.input {
					flex: 1;
					margin-left: 20rpx;
				}

				.search-btn {
					padding: 4rpx 20rpx;
					background: #ff5f01;
					border-radius: 8rpx;
					color: #fff;
					font-size: 28rpx;
				}
			}
		}

		.content {
			padding: 120rpx 20rpx 20rpx 20rpx;

			.swiper {
				//padding: 10px;
			}
		}
	}
</style>