<template>
	<view :style="[compStyle]">
		<view class="goods-box">
			<view class="hd">
				<view class="t1" :style="{ color: titleTxtConfig.color }">{{ titleTxtConfig.value }}</view>
				<view class="t2" :style="{ color: descTxtConfig.color }"> {{ descTxtConfig.value }}</view>
			</view>
			<view class="scroll-box">
				<scroll-view class="scroll-Y" scroll-y="true">
					<view class="goods-list">
						<view v-for="(item, index) in goodsList" :key="index" class="goods-item"
							:style="{ borderRadius: itemRadius,backgroundColor:bgColor }" @click="itemClick(item)">
							<view class="tag">{{item.goods_type_text}}</view>
							<u-image  class="img" :src="$util.img(item.goods_img)" :border-radius="goodsItemRadius" height="334rpx"
								width="100%"></u-image>
							<view class="bottom">
								<view class="name line2">{{ item.goods_name }}</view>
								<view class="price">
									<goods-price :price="item.goods_price" />
								</view>
							</view>
						</view>
					</view>
				</scroll-view>
			</view>
		</view>
	</view>
</template>

<script>
	import CompMixin from '../mixins/comp.js'

	export default {
		components: {

		},
		name: 'GoodsList',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {
				goodsList: [],
			};
		},
		computed: {
			newsStyle() {
				return {
					padding: `${this.dataConfig.topConfig.val * 2}rpx ${this.dataConfig.prConfig.val * 2}rpx ${this.dataConfig.bottomConfig.val * 2}rpx`,
					marginTop: `${this.dataConfig.mbConfig.val * 2}rpx`,
					background: this.dataConfig.bgColor.color[0].item,
				}
			},
			titleTxtConfig() {
				return this.getAttr('titleTxtConfig', {})
			},
			descTxtConfig() {
				return this.getAttr('descTxtConfig', {})
			},
			goodsItemRadius() {
				const {
					goodsItemRadius
				} = this.dataConfig
				return goodsItemRadius.type ?
					`${goodsItemRadius.valList[0].val * 2}rpx ${goodsItemRadius.valList[1].val*2}rpx ${goodsItemRadius.valList[2].val*2}rpx ${goodsItemRadius.valList[3].val*2}rpx` :
					`${goodsItemRadius.val*2}rpx`
			},
			// 商品容器圆角
			itemRadius() {
				const {
					radius
				} = this.dataConfig
				return radius.type ?
					`${radius.valList[0].val * 2}rpx ${radius.valList[1].val*2}rpx ${radius.valList[2].val*2}rpx ${radius.valList[3].val*2}rpx` :
					`${radius.val*2}rpx`
			},
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		methods: {
			async init() {
				const {
					typeConfig,
					goodsList,
					classList,
					goodsSort,
					numberConfig
				} = this.dataConfig

				if (typeConfig.activeValue == 1) {
					this.goodsList = await this.$u.api.getDiyGoodsList({
						ids: goodsList.list.map(item => item.id),
						is_count: 0
					})
				} else if (typeConfig.activeValue == 2) {
					let sort_type = 5
					if (goodsSort.tabVal == 0)
						sort_type = 1
					else if (goodsSort.tabVal == 1)
						sort_type = 5
					else if (goodsSort.tabVal == 2)
						sort_type = 3

					this.goodsList = await this.$u.api.getDiyGoodsList({
						cid: classList.classVal,
						count: numberConfig.val,
						sort_type,
						is_count: 0
					})
				}
			},
			itemClick(row) {
				this.$kss.JumpPath(`/pages/goods/detail?id=${row.id}`)
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	// ::v-deep {
	// 	uni-image > img {
	// 			opacity: 1 !important;
	// 	}
	// }
	
	.goods-box {
		.hd {
			display: flex;
			align-items: center;
			padding: 20rpx 0;

			.t1 {
				font-weight: bold;
				font-size: 40rpx;
			}

			.t2 {
				font-size: 24rpx;
				margin-left: 20rpx;
			}
		}

		.scroll-box {
			width: 100%;

			.goods-list {
				width: 100%;
				height: 100%;
				display: flex;
				flex-wrap: wrap;

				.goods-item {
					display: flex;
					flex-direction: column;
					flex-basis: calc(calc(100% / 2) - 20rpx);
					margin: 10rpx;
					box-shadow: 0 4rpx 12rpx 4rpx rgba(0, 0, 0, 0.03);
					border-radius: 16rpx;
					position: relative;
					background-color: #fff;
					cursor: pointer;
					overflow: hidden;

					.tag {
						position: absolute;
						top: 8px;
						left: 8px;
						padding: 0 3px;
						z-index: 2;
						line-height: 20px;
						font-size: 11px;
						color: #fff;
						border-radius: 3px;
						background-color: rgba(7, 180, 255, 0.5);
					}

					.bottom {
						padding: 5px;

						.name {
							min-height: 38px;
						}

						.price {}
					}
				}
			}
		}
	}
</style>