<template>
	<view class="goods-box">
		<view class="title">选购商品</view>
		<view class="goods-list">
			<scroll-view :scroll-x="true" class="scroll-view_H">
				<view class="goods-item" v-for="item,index in splitData" :key="index"
					:class="{checked:item.is_must == 1 || checkSelected(item,index)}" @click="onClick(item,index)">
					<view class="img">
						<u-image width="100%" height="220rpx" :src="item.img" />
						<view class="txt">
							<text class="line2">{{item.name}}</text>
						</view>
						<text class="icon" @click.stop><u-icon name="search" size="28"
								@click="preview(item.img)" /></text>
					</view>
				</view>
			</scroll-view>
		</view>
	</view>
</template>

<script>
	import _ from 'lodash'

	export default {
		components: {

		},
		props: {
			source: {
				type: Object,
				default: () => {}
			},
		},
		data() {
			return {
				goodsList: []
			};
		},
		computed: {
			mustNumber() {
				return this.source.must_number || 0
			},
			splitData() {
				return this.source.split_data || []
			},
			selectedGoods() {
				let arr = []
				this.goodsList.forEach(item => {
					if (item.checked === true)
						arr.push(item)
				})
				return arr
			},
			selectedIds() {
				let arr = []
				this.selectedGoods.forEach(item => {
					arr.push(item.goods_id)
				})
				return arr
			},
		},
		watch: {

		},
		created() {

		},
		mounted() {
			this.init()
		},
		methods: {
			init() {
				// 初始化选中商品
				this.goodsList = this.splitData.map((item) => {
					return {
						...item,
						checked: item.is_must == 1 ? true : false,
					}
				})
				let selected_ids = []
				this.goodsList.forEach(item => {
					if (item.checked === true)
						selected_ids.push(item.goods_id)
				})
				if (selected_ids.length) {
					this.$emit('change', selected_ids)
				}
			},
			onClick(row, index) {
				if (row.is_must == 1) {
					this.$util.msg('必选商品无法取消！')
					return
				}
				if (this.goodsList[index].checked) {
					this.goodsList[index].checked = !this.goodsList[index].checked
					this.$emit('change', [...this.selectedIds])
				} else {
					if (this.selectedGoods.length < this.mustNumber) {
						this.goodsList[index].checked = !this.goodsList[index].checked
						this.$emit('change', [...this.selectedIds])
					} else {
						this.$util.msg(`超过可选商品上限[${this.mustNumber}]`)
						return
					}
				}
			},
			checkSelected(row, index) {
				return this.goodsList[index] && this.goodsList[index].checked === true
			}
		},
	};
</script>

<style scoped lang="scss" scoped>
	.goods-box {
		margin-top: 10rpx;
		padding: 0 30rpx;

		.title {
			padding: 8rpx 0;
			font-weight: bold;
		}
	}

	.goods-list {
		display: flex;
		align-items: center;
		gap: 10rpx;
		flex: 1;


		.goods-item {
			border: 1rpx solid rgba(0, 0, 0, 0);
			border-radius: 10rpx;
			font-size: 24rpx;
			position: relative;
			cursor: pointer;
			user-select: none;
			display: inline-flex;
			align-items: center;
			justify-content: center;
			overflow: hidden;
			width: 200rpx;

			.img {
				flex: 1;
				display: flex;
				align-items: center;
				justify-content: center;
				flex-direction: column;
				position: relative;

				&>.txt {
					display: flex;
					align-items: center;
					justify-content: center;
					width: 100%;
					height: 80rpx;
					padding: 8rpx;
					border-bottom-left-radius: 10rpx;
					border-bottom-right-radius: 10rpx;
					background-color: #F7F8FA;
					white-space: normal;
				}

				&>.icon {
					position: absolute;
					right: 5rpx;
					top: 5rpx;
					width: 40rpx;
					height: 40rpx;
					background-color: rgba(0, 0, 0, 0.4);
					border-radius: 2px;
					text-align: center;
					color: #fff;
					line-height: 1;
					display: flex;
					align-items: center;
					justify-content: center;
				}
			}
		}

		.goods-item+.goods-item {
			margin-left: 10rpx;
		}

		.checked {
			border: 1rpx solid #ee0a24;
			color: #ee0a24;

			.img {
				&>.txt {
					background-color: #FFF2F2;
				}
			}
		}
	}
</style>