<template>
	<view>
		<u-popup v-model="showLayer" mode="center" width="80%" :closeable="false" border-radius="10">
			<view class="content-box">
				<u-parse :html="data" :lazy-load="true" ></u-parse>
			</view>
		</u-popup>
	</view>
</template>

<script>
	export default {
		props: {
			data:{
				type:String,
				default:''
			},
		},
		data() {
			return {
				showLayer: false,

			}
		},
		methods: {
			show() {
				this.showLayer = true
			},
			close() {
				this.showLayer = false
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	.content-box{
		padding:  40rpx;
		max-height: 80vh;
	}
</style>