<template>
	<view :style="[compStyle]">
		<u-swiper v-if="imgUrls.length > 1" :height="heightConfig" :bg-color="bgColor" :list="imgUrls"
			:mode="indicatorShowConfig?'rect':'none'" :img-mode="imgMode" @click="handelItemClick"
			:border-radius="borderRadius"></u-swiper>
		<u-image v-else :src="imgUrls[0].image" :height="heightConfig" mode="scaleToFill" @click="handelItemClick(0)" />
	</view>
</template>

<script>
	import CompMixin from '../mixins/comp.js'
	export default {
		name: 'Ad',
		mixins: [CompMixin],
		data() {
			return {

			};
		},
		computed: {
			// 组件容器样式
			compStyle() {
				const re = {
					backgroundColor: this.bottomBgColor,
					backgroundImage: `url(${this.bottomBgPicConfig.src})`,
					backgroundRepeat: '',
					backgroundSize: '',
					marginTop: this.mbConfig,
					paddingTop: this.topConfig,
					paddingBottom: this.bottomConfig,
					paddingLeft: this.prConfig,
					paddingRight: this.prConfig,
				}
				if (this.bottomBgPicConfig.tabVal == 2) {
					re.backgroundSize = '100% 100%'
					re.backgroundRepeat = 'no-repeat'
				} else if (this.bottomBgPicConfig.tabVal == 1) {
					re.backgroundSize = '100%'
					re.backgroundRepeat = 'repeat'
				} else {
					re.backgroundSize = '100%'
					re.backgroundRepeat = 'no-repeat'
				}
				return re
			},
			// 图片轮播数据
			imgUrls() {
				return this.dataConfig.swiperConfig.list.map(item => {
					return {
						image: this.$util.img(item.img),
						title: item.imgTitle,
						url: item.info[0].value
					}
				})
			},
			bgColor() {
				return this.dataConfig.moduleColor.color[0].item
			},
			bottomBgColor() {
				return this.dataConfig.bottomBgColor.color[0].item
			},
			topConfig() {
				return `${this.dataConfig.topConfig.val * 2}rpx`
			},
			bottomConfig() {
				return `${this.dataConfig.topConfig.val * 2}rpx`
			},
			prConfig() {
				return `${this.dataConfig.prConfig.val * 2}rpx`
			},
			mbConfig() {
				return `${this.dataConfig.mbConfig.val * 2}rpx`
			},
			heightConfig() {
				return this.getAttr('heightConfig.val', 150) * 2
			},
			imgMode() {
				const fillConifg = this.getAttr('fillConifg.tabVal', 0)
				if (fillConifg == 0)
					return 'scaleToFill'
				else if (fillConifg == 1)
					return 'aspectFit'
				else if (fillConifg == 2)
					return 'aspectFill'
				else
					return 'scaleToFill'
			},
			indicatorShowConfig() {
				return !this.getAttr('indicatorShowConfig.tabVal', 0) ? true : false
			},
			bottomBgPicConfig() {
				return this.getAttr('bottomBgPicConfig', {
					src: '',
					tabVal: 0
				})
			},
			borderRadius() {
				return this.getAttr('fillet.val', 0) * 2
			}
		},
		mounted() {

		},
		methods: {
			handelItemClick(index) {
				this.$kss.JumpPath(this.imgUrls[index].url)
			}
		}
	}
</script>

<style lang="scss" scoped scoped>

</style>