<template>
	<view class="comp-box" :style="[compStyle]">
		<view class="wrap" :style="[compContentStyle2]">
			<view class="level-up" @click="handelClick">
				<view class="left">
					<u-image :src="$util.img('/statics/uni/img/common/svip_user.png')" width="40" height="40" />
					<text :style="[leftTextStyle]">{{ leftTextConfig.value }}</text>
				</view>
				<view class="right">
					<text :style="[rightTextStyle]">{{ rightTextConfig.value }}</text>
					<u-icon name="arrow-right"></u-icon>
				</view>
			</view>
		</view>
	</view>
</template>
<script>
	import CompMixin from '../mixins/comp.js'
	import _ from 'lodash'

	export default {
		components: {

		},
		name: 'LevelUp',
		props: {

		},
		mixins: [CompMixin],
		inject: {
			showMemberPrice: {
				default: () => {}
			}
		},
		data() {
			return {

			};
		},
		computed: {
			clickEventConfig() {
				return this.getAttr('clickEventConfig', {
					title: '点击事件',
					tabVal: 0,
					tabList: [{
							name: '跳转页面',
							content: [{
								title: '链接地址',
								type: 'input-link',
								value: {
									name: '升级会员',
									link: '/pages/ucenter_sub/upgrade/index',
								},
							}, ],
						},
						{
							name: '事件回调',
							content: [{
								title: '事件列表',
								type: 'select',
								value: 'member_price',
								list: [{
									label: '会员价',
									value: 'member_price',
								}, ],
							}, ],
						},
					],
				})
			},
			leftTextConfig() {
				return this.getAttr('leftTextConfig', {})
			},
			rightTextConfig() {
				return this.getAttr('rightTextConfig', {})
			},
			leftTextStyle() {
				const re = {
					color: this.leftTextConfig.color,
				}
				if (this.leftTextConfig.hasFontSize) {
					re.fontSize = `${this.leftTextConfig.fontSize}px`
				}
				if (this.leftTextConfig.hasFontBlod) {
					re.fontWeight = this.leftTextConfig.fontBlod ? 'bolder' : ''
				}
				return re
			},
			rightTextStyle() {
				const re = {
					color: this.rightTextConfig.color,
				}
				if (this.rightTextConfig.hasFontSize) {
					re.fontSize = `${this.rightTextConfig.fontSize}px`
				}
				if (this.rightTextConfig.hasFontBlod) {
					re.fontWeight = this.rightTextConfig.fontBlod ? 'bolder' : ''
				}
				return re
			},
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		methods: {
			async init() {},
			handelClick() {
				if (this.clickEventConfig.tabVal == 0) {
					const data = this.clickEventConfig.tabList[0].content
					this.$kss.JumpPath(data[0].value.link)
				} else if (this.clickEventConfig.tabVal == 1) {
					const data = this.clickEventConfig.tabList[1].content
					if (data[0].value == 'member_price') {
						this.doInjectMethod('showMemberPrice')
					}
				}
			},
			doInjectMethod(method_name) {
				if (_.isFunction(this[method_name])) {
					this[method_name]()
				} else {
					this.$util.msg('未检测到的事件方法！')
				}
			}
		}
	}
</script>
<style lang="scss" scoped scoped>
	.level-up {
		display: flex;
		align-items: center;
		justify-content: space-between;
		height: 66rpx;
		padding: 0 20rpx;
		background-color: #fae3bb;
		font-size: 24rpx;
		color: #b37400;
		border-radius: 10rpx;

		.left {
			display: flex;
			align-items: center;
			gap: 10rpx;
		}
	}
</style>