<template>
	<u-tabbar :height="110" :before-switch="beforeSwitch" :active-color='activeColor' :inactive-color="inactiveColor"
		:bg-color="bgColor" :list="list"></u-tabbar>
</template>

<script>
	import {
		mapActions,
		mapGetters
	} from 'vuex'
	export default {
		name: "tab-bar",
		props: {

		},
		data() {
			return {
				// 导航栏配置数据
				newData: null,
				showTabBar: false,
			};
		},
		computed: {
			...mapGetters(['deviceInfo', 'cartGoodsNum']),
			activeRouter() {
				return this.$Route.path
			},
			activeColor() {
				if (this.newData) {
					// 自定义
					if (this.newData.toneConfig.tabVal) {
						return this.newData.activeTxtColor.color[0].item
					}
					// 系统主题
					else {
						return 'var(--view-theme)'
					}
				} else
					return ''


				return this.newData ? this.newData.activeTxtColor.color[0].item : ''
			},
			inactiveColor() {
				if (this.newData) {
					// 自定义
					if (this.newData.toneConfig.tabVal) {
						return this.newData.txtColor.color[0].item
					}
					// 系统主题
					else {
						return '#1A1A1A'
					}
				} else
					return ''
			},
			bgColor() {
				return this.newData ? this.newData.bgColor.color[0].item : ''
			},
			list() {
				if (this.newData) {
					return this.newData.menuList.map(item => {
						if (item.link === `/pages/cart/index`) {
							return {
								iconPath: this.$util.img(item.imgList[1]),
								selectedIconPath: this.$util.img(item.imgList[0]),
								text: item.name,
								count: this.cartGoodsNum,
								isDot: false,
								customIcon: false,
								pagePath: item.link
							}
						} else
							return {
								iconPath: this.$util.img(item.imgList[1]),
								selectedIconPath: this.$util.img(item.imgList[0]),
								text: item.name,
								count: 0,
								isDot: false,
								customIcon: false,
								pagePath: item.link
							}
					})
				}
				return []
			},
		},
		mounted() {
			this.fetchData();
		},
		destroyed() {

		},
		methods: {
			async fetchData() {
				const res = await this.$u.api.getDiyNavigation({
					url: this.activeRouter
				})
				uni.setStorageSync('footerNavigation', res)
				this.newData = res
				this.showTabBar = !res.effectConfig.tabVal ? true : false
				this.$emit('newDataStatus', res.effectConfig.tabVal)
				uni.hideTabBar()
				// if (this.showTabBar) {
				// 	uni.showTabBar()
				// } else {
				// 	uni.hideTabBar()
				// }
			},
			beforeSwitch(res) {
				return true
			}
		}
	}
</script>

