import BuyButton from '../comp/BuyButton'
import CouponDetailPopup from '../comp/CouponDetailPopup'
import OfficialAccountQrcodePopup from '../comp/OfficialAccountQrcodePopup'
import BuyGrgoupButton from '../comp/BuyGrgoupButton'
import ChildCategoryPopup from '../comp/ChildCategoryPopup'
import CartBox from '../comp/CartBox'
import JoinCartButton from '../comp/JoinCartButton'
import ProductPopup from '../comp/ProductPopup'
import GoodsStoreNum from '../comp/GoodsStoreNum'
import CartPopup from '../comp/CartPopup'
import MinLevelPrice from '../comp/MinLevelPrice'

export default {
	components: {
		BuyButton,
		CouponDetailPopup,
		OfficialAccountQrcodePopup,
		BuyGrgoupButton,
		ChildCategoryPopup,
		CartBox,
		JoinCartButton,
		ProductPopup,
		GoodsStoreNum,
		CartPopup,
		MinLevelPrice
	},
	props: {
		dataConfig: {
			type: Object,
			default: () => {}
		},
		// 页面配置数据，对页面监听需要用到
		pageConfig: {
			type: Object,
			default: () => {}
		},
	},
	inject: ['injectPageConfig'],
	data() {
		return {

		}
	},
	computed: {
		// 组件名称
		compCnName() {
			return this.dataConfig.cname
		},
		compEnName() {
			return this.dataConfig.name
		},
		// 组件容器样式
		compStyle() {
			const re = {
				backgroundColor: this.bottomBgColor,
				backgroundImage: `url(${this.$util.img2(this.bottomBgPicConfig.src)})`,
				backgroundRepeat: '',
				backgroundSize: '',
				marginTop: this.mbConfig,
				paddingTop: this.topConfig,
				paddingBottom: this.bottomConfig,
				paddingLeft: this.prConfig,
				paddingRight: this.prConfig,
			}
			if (this.bottomBgPicConfig.tabVal == 2) {
				re.backgroundSize = '100% 100%'
				re.backgroundRepeat = 'no-repeat'
			} else if (this.bottomBgPicConfig.tabVal == 1) {
				re.backgroundSize = '100%'
				re.backgroundRepeat = 'repeat'
			} else {
				re.backgroundSize = '100%'
				re.backgroundRepeat = 'no-repeat'
			}
			return re
		},
		compWrapStyle() {
			const re = {
				background: `linear-gradient(90deg, ${this.moduleColor[0]} 0%, ${this.moduleColor[1]} 100%)`,
				borderRadius: `${this.radiusConfig}`,
				'box-shadow': `${this.shadowConfig}`
			}
			return re
		},
		// 组件内容渐变色+圆角
		compContentStyle() {
			let borderRadius = `${this.getAttr('fillet.val',0) * 2}rpx`;
			if (this.getAttr('fillet.type', 0)) {
				borderRadius =
					`${this.getAttr('fillet.valList[0].val',0) * 2}rpx ${this.getAttr('fillet.valList[1].val',0) * 2}rpx ${this.getAttr('fillet.valList[2].val',0) * 2}rpx ${this.getAttr('fillet.valList[3].val',0) * 2}rpx`;
			}
			return {
				borderRadius,
				background: `linear-gradient(90deg, ${this.moduleColor[0]} 0%, ${this.moduleColor[1]} 100%)`,
			};
		},
		compContentStyle2() {
			return {
				borderRadius: this.radiusConfig,
				background: `linear-gradient(90deg, ${this.moduleColor[0]} 0%, ${this.moduleColor[1]} 100%)`,
			};
		},
		// 组件背景色(弃用)
		bgColor() {
			return this.getAttr('bgColor.color[0].item', '#fff')
		},
		// 组件背景色
		moduleColor() {
			return this.getAttr('moduleColor.color', []).map(item => item.item)
		},
		// 组件容器背景色，正常情况下会被bgColor遮挡住
		bottomBgColor() {
			return this.getAttr('bottomBgColor.color[0].item', '#fff')
		},
		topConfig() {
			return `${this.getAttr('topConfig.val',0) * 2}rpx`
		},
		bottomConfig() {
			return `${this.getAttr('bottomConfig.val',0) * 2}rpx`
		},
		prConfig() {
			return `${this.getAttr('prConfig.val',0) * 2}rpx`
		},
		mbConfig() {
			return `${this.getAttr('mbConfig.val',0) * 2}rpx`
		},
		bottomBgPicConfig() {
			return this.getAttr('bottomBgPicConfig', {
				src: '',
				tabVal: 0
			})
		},
		radiusConfig() {
			const radius = this.getAttr('radius', {
				type: 0,
				valList: []
			})
			return radius.type ?
				`${radius.valList[0].val * 2}rpx ${radius.valList[1].val * 2}rpx ${radius.valList[2].val *2}rpx ${radius.valList[3].val * 2}rpx` :
				`${radius.val*2}rpx`
		},
		shadowConfig() {
			const shadow = this.getAttr('shadowConfig', {
				x: 0,
				y: 0,
				blur: 0,
				spread: 0,
				color: '#000',
				inset: false
			})
			let re = `${shadow.x}px ${shadow.y}px ${shadow.blur}px ${shadow.spread}px ${shadow.color}`
			if (shadow.inset) {
				re += " inset"
			}
			return re
		},
	},
	created() {

	},
	methods: {
		getAttr(key = '', defaultVal = undefined) {
			return this.$_.get(this.dataConfig, key, defaultVal)
		},
		setAttr(key, newVal) {
			return this.$_.set(this.dataConfig, key, newVal)
		},
		img(src) {
			return this.$util.img2(src)
		},
		getUrl(path = '', query = {}) {
			if (!path)
				return path
			const tmp = [path]

			const arr = []
			for (let k in query) {
				if (query[k])
					arr.push(`${k}=${query[k]}`)
			}
			tmp.push(arr.join("&"))
			return tmp.join('?')
		}
	}
};